const App: React.FC = () => {
  const { setOfflineMode } = usePlayerStore();

  useEffect(() => {
    const handleOnline = () => setOfflineMode(false);
    const handleOffline = () => setOfflineMode(true);

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    // Initial check
    setOfflineMode(!navigator.onLine);

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, [setOfflineMode]);

  return (
    <HashRouter>
      <Layout>
        <AnimatedRoutes />
      </Layout>
    </HashRouter>
  );
};

export default App;

import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import { Song, UserPlaylist, User, Friend, ChatMessage, PartySession, Artist } from '../types';
import { authService } from '../services/auth';
import { downloadSongWithProgress, OfflineStorage } from '../services/api';

interface PlayerState {
  isPlaying: boolean;
  isBuffering: boolean;
  isFullScreen: boolean;
  currentSong: Song | null;
  queue: Song[];
  history: Song[];
  likedSongs: Song[];
  favoriteArtists: Artist[];
  userPlaylists: UserPlaylist[];
  volume: number;
  isShuffling: boolean;
  streamingQuality: 'low' | 'normal' | 'high';
  musicSource: 'local' | 'youtube' | 'both';

  // Audio Engine State
  audioElement: HTMLAudioElement | null;
  duration: number;

  // Offline & Downloads
  isOfflineMode: boolean;
  downloadedSongIds: string[];
  activeDownload: Song | null;
  downloadProgress: number;

  // Auth
  currentUser: User | null;

  // Social
  friends: Friend[]; // Unified list
  searchResults: { name: string, email: string, image?: string }[];
  activeChatFriendId: string | null;
  partySession: PartySession | null;

  // Realtime Cleanup
  unsubscribers: Function[];

  // Actions
  setAudioElement: (el: HTMLAudioElement) => void;
  setDuration: (duration: number) => void;
  playSong: (song: Song, newQueue?: Song[]) => void;
  togglePlay: () => void;
  setIsPlaying: (isPlaying: boolean) => void;
  setIsBuffering: (isBuffering: boolean) => void;
  setFullScreen: (isFull: boolean) => void;
  nextSong: () => void;
  prevSong: () => void;
  addToQueue: (song: Song) => void;
  setQueue: (songs: Song[]) => void;
  setVolume: (val: number) => void;
  addToHistory: (song: Song) => void;
  toggleLike: (song: Song) => void;
  toggleArtistLike: (artist: Artist) => void;
  createPlaylist: (playlist: UserPlaylist) => void;
  importPlaylist: (playlist: UserPlaylist) => void;
  addSongToPlaylist: (playlistId: string, song: Song) => void;
  removePlaylist: (id: string) => void;
  setStreamingQuality: (quality: 'low' | 'normal' | 'high') => void;
  setMusicSource: (source: 'local' | 'youtube' | 'both') => void;
  startDownload: (song: Song, url: string, filename: string) => Promise<void>;

  // Network Actions
  setOfflineMode: (isOffline: boolean) => void;

  // Auth Actions
  loginUser: (user: User & { likedSongs?: Song[], history?: Song[], favoriteArtists?: Artist[], chats?: any }) => void;
  logoutUser: () => void;
  syncUserToCloud: (type?: 'public' | 'private' | 'both') => void;
  updateUserProfile: (name: string, image?: string) => void;
  initRealtimeListeners: () => void;

  // Social Actions
  searchUsers: (query: string) => Promise<void>;
  addContact: (email: string) => Promise<void>;
  refreshFriendsActivity: () => Promise<void>;
  openChat: (friendId: string | null) => void;
  sendMessage: (friendId: string, text: string) => void;
  startParty: () => void;
  stopParty: () => void;
}

export const usePlayerStore = create<PlayerState>()(
  persist(
    (set, get) => ({
      isPlaying: false,
      isBuffering: false,
      isFullScreen: false,
      currentSong: null,
      queue: [],
      history: [],
      likedSongs: [],
      favoriteArtists: [],
      userPlaylists: [],
      volume: 1,
      isShuffling: false,
      currentUser: null,
      streamingQuality: 'high',
      musicSource: 'both',

      // Audio Engine Initial
      audioElement: null,
      duration: 0,

      // Offline State
      isOfflineMode: !navigator.onLine,
      downloadedSongIds: [],
      activeDownload: null,
      downloadProgress: 0,

      // Social Initial State
      friends: [],
      searchResults: [],
      activeChatFriendId: null,
      partySession: null,
      unsubscribers: [],

      setAudioElement: (el) => set({ audioElement: el }),
      setDuration: (duration) => set({ duration }),

      setOfflineMode: (isOffline) => set({ isOfflineMode: isOffline }),

      playSong: (song, newQueue) => {
        const { addToHistory, currentUser } = get();
        addToHistory(song);

        if (currentUser && navigator.onLine) {
            authService.updateUserStatus('listening', song);
        }

        set((state) => ({
          currentSong: song,
          isPlaying: true,
          isBuffering: true, 
          queue: newQueue ? newQueue : state.queue,
          isFullScreen: false, 
        }));
      },

      togglePlay: () => set((state) => ({ isPlaying: !state.isPlaying })),

      setIsPlaying: (isPlaying) => {
          set({ isPlaying });
          const { currentUser, currentSong, isOfflineMode } = get();
          if (currentUser && !isPlaying && !isOfflineMode) {
             authService.updateUserStatus('online', currentSong);
          }
      },

      setIsBuffering: (isBuffering) => set({ isBuffering }),
      setFullScreen: (isFullScreen) => set({ isFullScreen }),

      nextSong: () => {
        const { queue, currentSong, isShuffling } = get();
        if (!currentSong) return;
        const currentIndex = queue.findIndex(s => s.id === currentSong.id);
        let nextIndex = isShuffling ? Math.floor(Math.random() * queue.length) : currentIndex + 1;
        if (nextIndex < queue.length) get().playSong(queue[nextIndex]);
        else set({ isPlaying: false });
      },

      prevSong: () => {
        const { queue, currentSong } = get();
        if (!currentSong) return;
        const currentIndex = queue.findIndex(s => s.id === currentSong.id);
        if (currentIndex - 1 >= 0) get().playSong(queue[currentIndex - 1]);
      },

      addToQueue: (song) => set((state) => ({ queue: [...state.queue, song] })),
      setQueue: (songs) => set({ queue: songs }),
      setVolume: (volume) => set({ volume }),
      setStreamingQuality: (quality) => set({ streamingQuality: quality }),
      setMusicSource: (source) => set({ musicSource: source }),

      addToHistory: (song) => {
          set((state) => {
            const newHistory = [song, ...state.history.filter(s => s.id !== song.id)].slice(0, 20);
            if(navigator.onLine) setTimeout(() => get().syncUserToCloud('private'), 1000);
            return { history: newHistory };
          });
      },

      toggleLike: (song) => {
          set((state) => {
            const isLiked = state.likedSongs.some(s => s.id === song.id);
            const newLiked = isLiked ? state.likedSongs.filter(s => s.id !== song.id) : [song, ...state.likedSongs];
            if(navigator.onLine) setTimeout(() => get().syncUserToCloud('private'), 1000);
            return { likedSongs: newLiked };
          });
      },

      toggleArtistLike: (artist) => {
          set((state) => {
              const isLiked = state.favoriteArtists.some(a => a.id === artist.id);
              const newLiked = isLiked 
                  ? state.favoriteArtists.filter(a => a.id !== artist.id) 
                  : [...state.favoriteArtists, artist];
              return { favoriteArtists: newLiked };
          });
      },

      createPlaylist: (playlist) => {
        set((state) => {
           const newPlaylists = [playlist, ...state.userPlaylists];
           if(navigator.onLine) authService.savePublicPlaylist(playlist);
           if (state.currentUser) {
             const updatedUser = { ...state.currentUser, playlists: newPlaylists };
             if(navigator.onLine) setTimeout(() => get().syncUserToCloud('private'), 1000);
             return { userPlaylists: newPlaylists, currentUser: updatedUser };
           }
           return { userPlaylists: newPlaylists };
        });
      },

      importPlaylist: (playlist) => {
        set((state) => {
           if (state.userPlaylists.some(p => p.id === playlist.id)) return {};
           const newPlaylists = [playlist, ...state.userPlaylists];
           if (state.currentUser) {
             const updatedUser = { ...state.currentUser, playlists: newPlaylists };
             if(navigator.onLine) setTimeout(() => get().syncUserToCloud('private'), 1000);
             return { userPlaylists: newPlaylists, currentUser: updatedUser };
           }
           return { userPlaylists: newPlaylists };
        });
      },

      addSongToPlaylist: (playlistId, song) => {
        set((state) => {
          const newPlaylists = state.userPlaylists.map(p => {
            if (p.id === playlistId) {
               const updated = { ...p, songs: [...p.songs, song] };
               if (p.songs.some(s => s.id === song.id)) return p;
               if(navigator.onLine) authService.savePublicPlaylist(updated);
               return updated;
            }
            return p;
          });
          if (state.currentUser) {
             const updatedUser = { ...state.currentUser, playlists: newPlaylists };
             if(navigator.onLine) setTimeout(() => get().syncUserToCloud('private'), 1000);
             return { userPlaylists: newPlaylists, currentUser: updatedUser };
           }
           return { userPlaylists: newPlaylists };
        });
      },

      removePlaylist: (id) => {
        set((state) => {
           const newPlaylists = state.userPlaylists.filter(p => p.id !== id);
           if (state.currentUser) {
             const updatedUser = { ...state.currentUser, playlists: newPlaylists };
             if(navigator.onLine) setTimeout(() => get().syncUserToCloud('private'), 1000);
             return { userPlaylists: newPlaylists, currentUser: updatedUser };
           }
           return { userPlaylists: newPlaylists };
        });
      },

      startDownload: async (song, url, filename) => {
         set({ activeDownload: song, downloadProgress: 0 });
         try {
             await downloadSongWithProgress(song.id, url, filename, (progress) => {
                 set({ downloadProgress: progress });
             });

             // Mark as downloaded in state
             set(state => {
                 const newDownloads = state.downloadedSongIds.includes(song.id) 
                    ? state.downloadedSongIds 
                    : [...state.downloadedSongIds, song.id];
                 return { downloadProgress: 100, downloadedSongIds: newDownloads };
             });

             // Wait a bit before closing progress
             setTimeout(() => {
                 set({ activeDownload: null, downloadProgress: 0 });
             }, 2000);
         } catch (e) {
             console.error("Download Error", e);
             set({ activeDownload: null, downloadProgress: 0 });
         }
      },

      loginUser: (user) => {
          set({ 
            currentUser: user, 
            userPlaylists: user.playlists || [],
            likedSongs: user.likedSongs || [],
            history: user.history || [],
            favoriteArtists: user.favoriteArtists || []
          });
          get().initRealtimeListeners();
      },

      initRealtimeListeners: () => {
         const { unsubscribers, currentUser } = get();
         unsubscribers.forEach(unsub => unsub());

         if (!currentUser || !navigator.onLine) {
             set({ unsubscribers: [] });
             return;
         }

         const newUnsubscribers: Function[] = [];

         const unsubUser = authService.subscribeToUserData((data) => {
             set((state) => {
                 const updatedUser = { ...state.currentUser, ...data } as User;
                 const existingFriends = state.friends;
                 const serverContactEmails = data.friends || [];
                 const serverChats = data.chats || {};

                 const mergedFriends: Friend[] = serverContactEmails.map((email: string) => {
                     const existing = existingFriends.find(f => f.id === email);
                     const chatHistory = serverChats[email] || serverChats[email.replace(/\./g, '_dot_')] || [];
                     return {
                         id: email,
                         name: existing?.name || email.split('@')[0], 
                         image: existing?.image || '',
                         status: existing?.status || 'offline', 
                         currentSong: existing?.currentSong || null, 
                         lastActive: existing?.lastActive || 0,
                         chatHistory: chatHistory
                     };
                 });

                 return {
                     currentUser: updatedUser,
                     friends: mergedFriends,
                     userPlaylists: data.playlists || state.userPlaylists
                 };
             });
         });
         newUnsubscribers.push(unsubUser);

         if (currentUser.friends && currentUser.friends.length > 0) {
             const unsubFriends = authService.subscribeToFriendsActivity(currentUser.friends, (friendsData) => {
                 set((state) => {
                     const updatedFriends = state.friends.map(f => {
                         const liveData = friendsData.find((d: any) => d.email === f.id);
                         if (liveData) {
                             return {
                                 ...f,
                                 name: liveData.name || f.name,
                                 image: liveData.image || f.image,
                                 status: liveData.currentActivity?.status || 'offline',
                                 currentSong: liveData.currentActivity?.song || null,
                                 lastActive: liveData.currentActivity?.timestamp || 0
                             };
                         }
                         return f;
                     });
                     return { friends: updatedFriends };
                 });
             });
             newUnsubscribers.push(unsubFriends);
         }

         set({ unsubscribers: newUnsubscribers });
      },

      logoutUser: async () => {
        get().unsubscribers.forEach(unsub => unsub());
        if(navigator.onLine) await authService.logout();
        set({ 
            currentUser: null, 
            userPlaylists: [],
            friends: [],
            partySession: null,
            likedSongs: [],
            history: [],
            favoriteArtists: [],
            unsubscribers: []
        });
      },

      syncUserToCloud: async (type = 'both') => {
         const { currentUser, userPlaylists, likedSongs, history, favoriteArtists, isOfflineMode } = get();
         if (!currentUser || isOfflineMode) return;
         const updatedUser = { ...currentUser, playlists: userPlaylists };
         try {
             if (type === 'public' || type === 'both') await authService.syncPublicProfile(updatedUser);
             if (type === 'private' || type === 'both') await authService.syncPrivateData(updatedUser, { likedSongs, history, favoriteArtists });
         } catch (e) {
             console.error("Sync failed", e);
         }
      },

      updateUserProfile: (name, image) => {
        set((state) => {
          if (!state.currentUser) return {};
          const updatedUser = { 
              ...state.currentUser, 
              name: name,
              image: image !== undefined ? image : state.currentUser.image 
          };
          setTimeout(() => get().syncUserToCloud('public'), 100);
          return { currentUser: updatedUser };
        });
      },

      searchUsers: async (query) => {
          try {
              if (!navigator.onLine) return;
              const results = await authService.searchUsers(query);
              const { currentUser } = get();
              const filtered = results.filter(u => u.email !== currentUser?.email);
              set({ searchResults: filtered });
          } catch (e) { console.error(e); }
      },

      addContact: async (email) => {
          const { currentUser } = get();
          if (!currentUser || !navigator.onLine) return;
          await authService.addContact(email);
          set((state) => {
              if (state.friends.some(f => f.id === email)) return {};
              const newFriend: Friend = {
                  id: email,
                  name: email.split('@')[0],
                  image: '',
                  status: 'offline',
                  lastActive: 0,
                  chatHistory: []
              };
              return { 
                  friends: [...state.friends, newFriend],
                  activeChatFriendId: email 
              };
          });
          setTimeout(() => {
              get().initRealtimeListeners();
          }, 500);
      },

      refreshFriendsActivity: async () => {
          get().initRealtimeListeners();
      },

      openChat: (friendId) => set({ activeChatFriendId: friendId }),

      sendMessage: async (friendId, text) => {
          const { currentUser } = get();
          if (!currentUser) return;

          const newMessage: ChatMessage = {
              id: `msg-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
              senderId: currentUser.email,
              text,
              timestamp: Date.now()
          };

          set((state) => {
              const updatedFriends = state.friends.map(f => {
                  if (f.id === friendId) {
                      return { ...f, chatHistory: [...f.chatHistory, newMessage] };
                  }
                  return f;
              });
              return { friends: updatedFriends };
          });

          if(navigator.onLine) {
             await authService.sendChatMessage(currentUser.email, friendId, newMessage);
          }
      },

      startParty: () => set((state) => {
         if (!state.currentUser) return {};
         return {
             partySession: {
                 isActive: true,
                 hostId: 'me',
                 hostName: state.currentUser.name,
                 listeners: state.activeChatFriendId ? [state.activeChatFriendId] : []
             }
         }
      }),

      stopParty: () => set({ partySession: null })
    }),
    {
      name: 'vibestream-storage',
      partialize: (state) => ({ 
        history: state.history, 
        volume: state.volume,
        likedSongs: state.likedSongs,
        favoriteArtists: state.favoriteArtists,
        userPlaylists: state.userPlaylists,
        currentUser: state.currentUser,
        streamingQuality: state.streamingQuality,
        musicSource: state.musicSource, // Persist selection
        downloadedSongIds: state.downloadedSongIds,
      }), 
    }
  )
);

import React, { useRef, useEffect } from 'react';
import { usePlayerStore } from '../store/playerStore';
import { api, getAudioUrl, getOfflineAudioUrl, getImageUrl } from '../services/api';

export const AudioController: React.FC = () => {
  const audioRef = useRef<HTMLAudioElement>(null);

  const { 
    currentSong, 
    isPlaying, 
    setIsPlaying, 
    setIsBuffering, 
    nextSong, 
    prevSong,
    setAudioElement,
    setDuration,
    duration,
    streamingQuality,
    isOfflineMode,
    downloadedSongIds
  } = usePlayerStore();

  // Register audio element in store on mount
  useEffect(() => {
    if (audioRef.current) {
        setAudioElement(audioRef.current);
    }
  }, [setAudioElement]);

  // Handle Playback State
  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;

    if (isPlaying && audio.paused) {
        audio.play().catch(e => {
            console.warn("Play blocked or interrupted", e);
            setIsPlaying(false);
        });
    } else if (!isPlaying && !audio.paused) {
        audio.pause();
    }
  }, [isPlaying, setIsPlaying]);

  // Handle Source Loading
  useEffect(() => {
    if (!currentSong || !audioRef.current) return;

    const loadSource = async () => {
        let url = '';

        // 1. Check Offline Storage
        if (isOfflineMode || downloadedSongIds.includes(currentSong.id)) {
            const blobUrl = await getOfflineAudioUrl(currentSong.id);
            if (blobUrl) url = blobUrl;
            else if (isOfflineMode) { setIsPlaying(false); return; }
        }

        // 2. Check Standard Download URLs
        if (!url && !isOfflineMode && currentSong.downloadUrl && currentSong.downloadUrl.length > 0) {
             url = getAudioUrl(currentSong.downloadUrl, streamingQuality);
        }

        // 3. Lazy Load Stream
        if (!url && !isOfflineMode) {
             try {
                 setIsBuffering(true);
                 const streamData = await api.getStreamInfo(currentSong.id);
                 if (streamData && streamData.stream_url) {
                     url = streamData.stream_url;
                 }
             } catch(e) {
                 console.error("Failed to fetch stream", e);
             }
        }

        if (url && audioRef.current && audioRef.current.src !== url) {
            const wasPlaying = isPlaying;
            audioRef.current.src = url;
            audioRef.current.load();
            if (wasPlaying) {
                 audioRef.current.play().catch(() => setIsPlaying(false));
            }
        }
    };

    loadSource();
  }, [currentSong?.id, streamingQuality, isOfflineMode, downloadedSongIds]);

  // Handle Media Session (Notification Controls)
  useEffect(() => {
    if (!currentSong || !('mediaSession' in navigator)) return;

    const artistName = currentSong.artists?.primary?.[0]?.name || "Unknown";
    const hqImage = getImageUrl(currentSong.image);

    navigator.mediaSession.metadata = new MediaMetadata({
      title: currentSong.name,
      artist: artistName,
      album: currentSong.album?.name || "Single",
      artwork: [
          { src: hqImage, sizes: '96x96', type: 'image/jpeg' },
          { src: hqImage, sizes: '128x128', type: 'image/jpeg' },
          { src: hqImage, sizes: '192x192', type: 'image/jpeg' },
          { src: hqImage, sizes: '256x256', type: 'image/jpeg' },
          { src: hqImage, sizes: '384x384', type: 'image/jpeg' },
          { src: hqImage, sizes: '512x512', type: 'image/jpeg' },
      ]
    });

    navigator.mediaSession.setActionHandler('play', () => setIsPlaying(true));
    navigator.mediaSession.setActionHandler('pause', () => setIsPlaying(false));
    navigator.mediaSession.setActionHandler('previoustrack', prevSong);
    navigator.mediaSession.setActionHandler('nexttrack', nextSong);

    // Cleanup
    return () => {
         if ('mediaSession' in navigator) {
             navigator.mediaSession.metadata = null;
         }
    };
  }, [currentSong, setIsPlaying, prevSong, nextSong]);

  const handleTimeUpdate = () => {
      // PERFORMANCE FIX: 
      // Do NOT update store on every tick. Only update duration if it changes.
      // UI components should read currentTime directly via requestAnimationFrame
      if (audioRef.current) {
          const dur = audioRef.current.duration;
          // Only update if valid and significantly different to avoid loops
          if (dur && dur !== Infinity && !isNaN(dur) && Math.abs(dur - duration) > 1) {
              setDuration(dur);
          }
      }
  };

  return (
    <audio 
        ref={audioRef}
        preload="auto"
        onTimeUpdate={handleTimeUpdate}
        onLoadedMetadata={handleTimeUpdate}
        onEnded={nextSong}
        onWaiting={() => setIsBuffering(true)}
        onPlaying={() => setIsBuffering(false)}
        onCanPlay={() => setIsBuffering(false)}
        onPause={() => {
            if (isPlaying && !audioRef.current?.seeking) setIsPlaying(false);
        }}
        onPlay={() => !isPlaying && setIsPlaying(true)}
    />
  );
};

import React, { useEffect, useState } from 'react';
import { Play, Pause, SkipBack, SkipForward, ChevronDown, MoreHorizontal, Download, ListMusic, Heart, Loader2, Shuffle, Repeat, PlusCircle, CheckCircle2, Disc, User, Share2, ListPlus, Radio, Mic2, Moon, Info } from 'lucide-react';
import { usePlayerStore } from '../store/playerStore';
import { api, getImageUrl } from '../services/api';
import { AnimatePresence, motion } from 'framer-motion';
import { useNavigate } from 'react-router-dom';

export const Player: React.FC = () => {
  const { 
    currentSong, 
    isPlaying, 
    isBuffering,
    isFullScreen,
    setFullScreen,
    togglePlay, 
    nextSong, 
    prevSong,
    likedSongs,
    toggleLike,
    isShuffling,
    downloadedSongIds,
    addToQueue,
    startDownload,
    duration, 
    audioElement
  } = usePlayerStore();

  const navigate = useNavigate();

  const [dominantColor, setDominantColor] = useState<string>('#121212');
  const [isDragging, setIsDragging] = useState(false);
  const [localProgress, setLocalProgress] = useState(0);

  const [isMoreMenuOpen, setIsMoreMenuOpen] = useState(false);
  const [isDownloadExpanded, setIsDownloadExpanded] = useState(false);

  const [sleepTimerId, setSleepTimerId] = useState<number | null>(null);
  const [touchStart, setTouchStart] = useState<{x: number, y: number} | null>(null);

  const isLiked = currentSong ? likedSongs.some(s => s.id === currentSong.id) : false;
  const isDownloaded = currentSong ? downloadedSongIds.includes(currentSong.id) : false;

  // PERFORMANCE FIX: Use requestAnimationFrame for smooth UI updates
  // This prevents the global store from updating 60 times a second, which was causing the lag.
  useEffect(() => {
    let rafId: number;

    const updateProgress = () => {
        if (audioElement && !isDragging) {
            setLocalProgress(audioElement.currentTime);
        }
        if (isPlaying) {
            rafId = requestAnimationFrame(updateProgress);
        }
    };

    if (isPlaying) {
        rafId = requestAnimationFrame(updateProgress);
    } else if (audioElement) {
        // Update once if paused to ensure UI matches audio state
        setLocalProgress(audioElement.currentTime);
    }

    return () => {
        if (rafId) cancelAnimationFrame(rafId);
    };
  }, [isPlaying, audioElement, isDragging]);

  // Extract color from image
  useEffect(() => {
    if (!currentSong) return;
    const imgUrl = getImageUrl(currentSong.image);
    const img = new Image();
    img.crossOrigin = "Anonymous";
    img.src = imgUrl;

    img.onload = () => {
      try {
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        if (!ctx) return;
        canvas.width = 1; 
        canvas.height = 1;
        ctx.drawImage(img, 0, 0, 1, 1);
        const [r, g, b] = ctx.getImageData(0, 0, 1, 1).data;
        setDominantColor(`rgb(${Math.max(20, r - 30)},${Math.max(20, g - 30)},${Math.max(20, b - 30)})`);
      } catch (e) {
        setDominantColor('#181818'); 
      }
    };
    img.onerror = () => setDominantColor('#181818');
  }, [currentSong?.id]);

  // Reset download expansion when menu closes or song changes
  useEffect(() => {
      if (!isMoreMenuOpen) setIsDownloadExpanded(false);
  }, [isMoreMenuOpen, currentSong?.id]);

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const time = parseFloat(e.target.value);
    setLocalProgress(time);
    if (audioElement) audioElement.currentTime = time;
  };

  const formatTime = (seconds: number) => {
    if (!seconds || isNaN(seconds)) return "-:--";
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  // --- ACTIONS FOR MORE MENU ---
  const handleAddToQueue = () => {
      if(currentSong) {
          addToQueue(currentSong);
          setIsMoreMenuOpen(false);
      }
  };

  const handleShare = async () => {
      if(!currentSong) return;
      const shareData = {
          title: currentSong.name,
          text: `Listen to ${currentSong.name} by ${currentSong.artists.primary[0].name}`,
          url: window.location.href
      };

      if (navigator.share) {
          try {
              await navigator.share(shareData);
          } catch(e) { console.log(e); }
      } else {
          navigator.clipboard.writeText(shareData.url);
      }
      setIsMoreMenuOpen(false);
  };

  const handleSleepTimer = () => {
      if (sleepTimerId) {
          clearTimeout(sleepTimerId);
          setSleepTimerId(null);
      } else {
          // Set for 30 mins
          const id = window.setTimeout(() => {
              if (audioElement) audioElement.pause();
              setSleepTimerId(null);
          }, 30 * 60 * 1000); 
          setSleepTimerId(id);
      }
      setIsMoreMenuOpen(false);
  };

  const handleGoToRadio = async () => {
      if(!currentSong) return;
      setIsMoreMenuOpen(false);

      try {
         const recommendations = await api.getRecommendations(currentSong.id);
         if (recommendations.length > 0) {
             recommendations.forEach(s => addToQueue(s));
             alert(`Added ${recommendations.length} recommended songs to queue.`);
         } else {
             const query = currentSong.artists.primary[0]?.name || currentSong.name;
             const songs = await api.searchSongs(query);
             const newSongs = songs.filter(s => s.id !== currentSong.id);
             if (newSongs.length > 0) {
                 newSongs.slice(0, 10).forEach(s => addToQueue(s));
             }
         }
      } catch(e) {
          console.error("Radio failed", e);
      }
  };

  const handleDownloadSelect = (url: string, quality: string) => {
      if(!currentSong) return;
      const filename = `${currentSong.name} (${quality}) - ${currentSong.artists.primary[0]?.name || 'Artist'}.mp3`;
      startDownload(currentSong, url, filename);
      setIsMoreMenuOpen(false);
      setIsDownloadExpanded(false);
  };

  const handleTouchStart = (e: React.TouchEvent) => {
    setTouchStart({ x: e.targetTouches[0].clientX, y: e.targetTouches[0].clientY });
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    if (!touchStart) return;
    const touchEndX = e.changedTouches[0].clientX;
    const touchEndY = e.changedTouches[0].clientY;
    const diffX = touchStart.x - touchEndX;
    const diffY = touchStart.y - touchEndY;

    if (Math.abs(diffX) > 50 && Math.abs(diffX) > Math.abs(diffY)) {
      if (diffX > 0) nextSong();
      else prevSong();
    }
    if (diffY < -80 && Math.abs(diffY) > Math.abs(diffX) && !isMoreMenuOpen) {
        setFullScreen(false);
    }
    setTouchStart(null);
  };

  if (!currentSong) return null;

  const imageUrl = getImageUrl(currentSong.image);
  const primaryArtistName = currentSong.artists?.primary?.[0]?.name || "Unknown";

  return (
    <>
        <AnimatePresence mode="wait">
            {isFullScreen ? (
                <motion.div 
                    key="full-player"
                    initial={{ y: "100%" }}
                    animate={{ y: 0 }}
                    exit={{ y: "100%" }}
                    transition={{ type: "spring", damping: 30, stiffness: 300, mass: 0.8 }}
                    className="fixed inset-0 z-[200] flex flex-col bg-[#121212] isolate overflow-hidden"
                    onClick={(e) => e.stopPropagation()}
                    onTouchStart={handleTouchStart}
                    onTouchEnd={handleTouchEnd}
                >
                    {/* Background */}
                    <div 
                        className="absolute inset-0 z-[-1]"
                        style={{ 
                            background: `linear-gradient(to bottom, ${dominantColor}, #121212)`,
                        }}
                    />

                    {/* FULL PLAYER CONTENT */}
                    <div className="relative z-10 flex flex-col h-full px-6 pt-safe-top pb-safe-bottom">

                        {/* Header */}
                        <div className="flex items-center justify-between h-16 shrink-0 mt-2">
                            <button onClick={() => setFullScreen(false)} className="p-2 -ml-2 rounded-full hover:bg-white/10 shrink-0">
                                <ChevronDown size={28} className="text-white" />
                            </button>
                            <span className="text-[11px] font-bold tracking-[0.15em] uppercase text-white/70">
                                Now Playing
                            </span>
                            <button onClick={() => setIsMoreMenuOpen(true)} className="p-2 -mr-2 rounded-full hover:bg-white/10 shrink-0">
                                <MoreHorizontal size={24} className="text-white" />
                            </button>
                        </div>

                        {/* Main Artwork Area */}
                        <div className="flex-1 flex flex-col justify-center min-h-0 relative my-4">
                            <div className="relative w-full aspect-square max-w-[340px] mx-auto shadow-2xl rounded-xl overflow-hidden">
                                <img 
                                    src={imageUrl} 
                                    alt="Cover"
                                    className="w-full h-full object-cover"
                                />
                            </div>
                        </div>

                        {/* Info & Controls */}
                        <div className="flex flex-col gap-6 mb-10">
                            <div className="flex items-center justify-between">
                                <div className="flex flex-col overflow-hidden mr-4 min-w-0">
                                    <h2 className="text-2xl font-bold text-white truncate">
                                        {currentSong.name}
                                    </h2>
                                    <p className="text-lg text-white/70 truncate">
                                        {primaryArtistName}
                                    </p>
                                </div>
                                <button onClick={() => toggleLike(currentSong)} className="shrink-0">
                                    {isLiked ? <CheckCircle2 size={28} className="text-[#1DB954] fill-black" /> : <PlusCircle size={28} className="text-white/70" />}
                                </button>
                            </div>

                            {/* Scrubber - Improved Hit Area */}
                            <div className="flex flex-col gap-2 pt-2">
                                {/* Container with larger height for touch target */}
                                <div className="relative h-6 w-full flex items-center group cursor-pointer">

                                     {/* Background Track */}
                                     <div className="absolute left-0 right-0 h-1.5 bg-white/20 rounded-full overflow-hidden">
                                         {/* Progress Fill */}
                                         <div 
                                            className="h-full bg-white rounded-full transition-all duration-75 ease-out" 
                                            style={{ width: `${(localProgress / (duration || 1)) * 100}%` }}
                                         />
                                     </div>

                                     {/* Thumb (Dot) - Positioned based on progress */}
                                     <div 
                                        className="absolute h-3.5 w-3.5 bg-white rounded-full shadow-md scale-100 transition-transform active:scale-125 z-10 pointer-events-none"
                                        style={{ left: `calc(${(localProgress / (duration || 1)) * 100}% - 7px)` }}
                                     />

                                     {/* Interaction Layer (Invisible Input) */}
                                     <input 
                                        type="range" 
                                        min="0" 
                                        max={duration || 100} 
                                        step="any"
                                        value={localProgress}
                                        onChange={handleSeek}
                                        onMouseDown={() => setIsDragging(true)}
                                        onTouchStart={() => setIsDragging(true)}
                                        onMouseUp={() => setIsDragging(false)}
                                        onTouchEnd={() => setIsDragging(false)}
                                        className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-20"
                                    />
                                </div>
                                <div className="flex justify-between text-[11px] text-white/50 font-mono font-medium -mt-1">
                                    <span>{formatTime(localProgress)}</span>
                                    <span>{formatTime(duration)}</span>
                                </div>
                            </div>

                            {/* Controls */}
                            <div className="flex items-center justify-between px-2">
                                <button className={`shrink-0 ${isShuffling ? 'text-[#1DB954]' : 'text-white/40'}`}><Shuffle size={20} /></button>
                                <button onClick={prevSong} className="shrink-0"><SkipBack size={32} className="text-white" fill="white" /></button>
                                <button 
                                    onClick={togglePlay}
                                    className="w-16 h-16 bg-white rounded-full flex items-center justify-center hover:scale-105 active:scale-95 transition-transform shrink-0"
                                >
                                    {isBuffering ? <Loader2 size={32} className="animate-spin text-black" /> : isPlaying ? <Pause size={32} fill="black" className="text-black" /> : <Play size={32} fill="black" className="ml-1 text-black" />}
                                </button>
                                <button onClick={nextSong} className="shrink-0"><SkipForward size={32} className="text-white" fill="white" /></button>
                                <button className="text-white/40 shrink-0"><Repeat size={20} /></button>
                            </div>

                            {/* Bottom Row */}
                            <div className="flex items-center justify-between px-4">
                                <button className="text-white/50 shrink-0 hover:text-white transition-colors p-2">
                                    <Mic2 size={22} />
                                </button>
                                <button className="text-white/50 shrink-0 hover:text-white transition-colors p-2"><ListMusic size={22} /></button>
                            </div>
                        </div>
                    </div>

                    {/* More Menu (Enhanced) */}
                    <AnimatePresence>
                        {isMoreMenuOpen && (
                            <motion.div 
                                initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
                                className="absolute inset-0 z-[250] bg-black/60 backdrop-blur-sm flex flex-col justify-end"
                                onClick={() => setIsMoreMenuOpen(false)}
                            >
                                <motion.div 
                                    initial={{ y: "100%" }} animate={{ y: 0 }} exit={{ y: "100%" }}
                                    transition={{ type: "tween", ease: "circOut", duration: 0.3 }}
                                    drag="y"
                                    dragConstraints={{ top: 0 }}
                                    dragElastic={{ top: 0, bottom: 0.2 }}
                                    onDragEnd={(_, info) => {
                                        if (info.offset.y > 100 || info.velocity.y > 100) {
                                            setIsMoreMenuOpen(false);
                                        }
                                    }}
                                    className="bg-[#242424] rounded-t-2xl flex flex-col max-h-[85vh] overflow-y-auto pb-6"
                                    onClick={e => e.stopPropagation()}
                                >
                                    {/* Drag Handle */}
                                    <div className="w-full flex justify-center pt-4 pb-2">
                                        <div className="w-10 h-1 bg-white/20 rounded-full"></div>
                                    </div>

                                    {/* Song Context Info */}
                                    <div className="flex items-center gap-3 px-6 pb-4">
                                        <img src={getImageUrl(currentSong.image)} className="w-12 h-12 rounded-md object-cover shadow-lg" alt="" />
                                        <div>
                                            <div className="font-bold text-white text-[15px]">{currentSong.name}</div>
                                            <div className="text-sm text-white/60">{primaryArtistName}</div>
                                        </div>
                                    </div>

                                    {/* Inline Accordion Download UI */}
                                    <div className="px-6 py-2">
                                        <div className={`rounded-xl transition-all border overflow-hidden ${isDownloadExpanded ? 'bg-[#2A2A2A] border-white/10' : 'bg-[#333] border-white/5'}`}>
                                            <button 
                                                onClick={() => { 
                                                    if(isDownloaded) return; // Already downloaded
                                                    setIsDownloadExpanded(!isDownloadExpanded);
                                                }} 
                                                className={`w-full flex items-center justify-between p-4 ${isDownloaded ? 'cursor-default' : 'cursor-pointer'}`}
                                            >
                                                <div className="flex items-center gap-3">
                                                      <div className={`p-2 rounded-full ${isDownloaded ? 'bg-[#1DB954]/20 text-[#1DB954]' : 'bg-white/10 text-white'}`}>
                                                      <Download size={20} />
                                                      </div>
                                                      <div className="flex flex-col items-start">
                                                          <span className={`text-sm font-bold ${isDownloaded ? 'text-[#1DB954]' : 'text-white'}`}>
                                                              {isDownloaded ? 'Downloaded' : 'Download'}
                                                          </span>
                                                          <span className="text-[10px] text-white/50 font-medium">
                                                          {isDownloaded ? 'Available offline' : (isDownloadExpanded ? 'Select Quality' : 'Tap to choose quality')}
                                                          </span>
                                                      </div>
                                                </div>
                                                {isDownloaded ? <CheckCircle2 size={20} className="text-[#1DB954]" /> : (
                                                    <ChevronDown size={20} className={`text-white/50 transition-transform ${isDownloadExpanded ? 'rotate-180' : ''}`} />
                                                )}
                                            </button>

                                            {/* Expanded Options */}
                                            <AnimatePresence>
                                                {isDownloadExpanded && !isDownloaded && (
                                                    <motion.div 
                                                        initial={{ height: 0, opacity: 0 }}
                                                        animate={{ height: 'auto', opacity: 1 }}
                                                        exit={{ height: 0, opacity: 0 }}
                                                        className="border-t border-white/5 bg-[#252525]"
                                                    >
                                                        {(currentSong.downloadUrl && currentSong.downloadUrl.length > 0) ? currentSong.downloadUrl.slice().sort((a,b) => parseInt(b.quality.replace(/\D/g, '')) - parseInt(a.quality.replace(/\D/g, ''))).map((opt) => (
                                                            <button
                                                                key={opt.quality}
                                                                onClick={() => handleDownloadSelect(opt.url, opt.quality)}
                                                                className="w-full flex items-center justify-between px-4 py-3 hover:bg-white/5 transition-colors group border-b border-white/5 last:border-0"
                                                            >
                                                                <div className="flex flex-col items-start">
                                                                    <span className="text-white font-medium text-sm">{opt.quality}</span>
                                                                    <span className="text-[10px] text-white/40 group-hover:text-white/60">
                                                                        {opt.quality.includes('320') ? 'Best Quality (~8MB)' : opt.quality.includes('160') ? 'Good Balance (~4MB)' : 'Data Saver'}
                                                                    </span>
                                                                </div>
                                                                <Download size={16} className="text-white/20 group-hover:text-white" />
                                                            </button>
                                                        )) : (
                                                            <button
                                                                onClick={async () => {
                                                                    const info = await api.getStreamInfo(currentSong.id);
                                                                    if(info?.stream_url) handleDownloadSelect(info.stream_url, 'Standard');
                                                                }}
                                                                className="w-full flex items-center justify-between px-4 py-3 hover:bg-white/5 transition-colors group"
                                                            >
                                                                <div className="flex flex-col items-start">
                                                                    <span className="text-white font-medium text-sm">Download High Quality</span>
                                                                    <span className="text-[10px] text-white/40 group-hover:text-white/60">Fetch & Save</span>
                                                                </div>
                                                                <Download size={16} className="text-white/20 group-hover:text-white" />
                                                            </button>
                                                        )}
                                                    </motion.div>
                                                )}
                                            </AnimatePresence>
                                        </div>
                                    </div>

                                    {/* Menu Actions List */}
                                    <div className="flex flex-col py-2">

                                        <button onClick={() => { toggleLike(currentSong); setIsMoreMenuOpen(false); }} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Heart size={24} className={isLiked ? "text-[#1DB954] fill-[#1DB954]" : "text-white/80"} />
                                            <span className="text-white font-medium">{isLiked ? 'Liked' : 'Like'}</span>
                                        </button>

                                        <button onClick={handleAddToQueue} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <ListPlus size={24} className="text-white/80" />
                                            <span className="text-white font-medium">Add to queue</span>
                                        </button>

                                        <button onClick={handleShare} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Share2 size={24} className="text-white/80" />
                                            <span className="text-white font-medium">Share</span>
                                        </button>

                                        <button onClick={() => { setIsMoreMenuOpen(false); navigate(`/artist/${currentSong.artists.primary[0].id}`, { state: { artist: currentSong.artists.primary[0] } }); }} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <User size={24} className="text-white/80" />
                                            <span className="text-white font-medium">View Artist</span>
                                        </button>

                                        <button onClick={() => { setIsMoreMenuOpen(false); navigate(`/album/${currentSong.album.id}`); }} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Disc size={24} className="text-white/80" />
                                            <span className="text-white font-medium">View Album</span>
                                        </button>

                                        <button onClick={handleSleepTimer} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Moon size={24} className={sleepTimerId ? "text-[#1DB954]" : "text-white/80"} />
                                            <span className="text-white font-medium">{sleepTimerId ? 'Stop Sleep Timer' : 'Sleep Timer (30 mins)'}</span>
                                        </button>

                                        <button onClick={handleGoToRadio} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Radio size={24} className="text-white/80" />
                                            <span className="text-white font-medium">Go to Song Radio</span>
                                        </button>

                                        <button className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Info size={24} className="text-white/80" />
                                            <span className="text-white font-medium">Show credits</span>
                                        </button>

                                    </div>

                                </motion.div>
                            </motion.div>
                        )}
                    </AnimatePresence>
                </motion.div>
            ) : (
                <motion.div 
                    key="mini-player"
                    initial={{ y: 50, opacity: 0 }}
                    animate={{ y: 0, opacity: 1 }}
                    exit={{ y: 50, opacity: 0 }}
                    transition={{ type: "spring", stiffness: 400, damping: 30 }}
                    className="fixed bottom-[68px] md:bottom-4 left-2 right-2 md:left-1/2 md:-translate-x-1/2 md:w-[450px] h-[56px] z-[150] cursor-pointer isolate"
                    onClick={() => setFullScreen(true)}
                >
                    {/* Background */}
                    <div 
                        className="absolute inset-0 z-[-1] rounded-lg shadow-xl overflow-hidden"
                        style={{ backgroundColor: dominantColor }}
                    >
                         <div className="absolute inset-0 bg-black/20" />
                    </div>

                    <div className="flex items-center h-full px-2 gap-3">
                        {/* Image */}
                        <div className="h-10 w-10 shrink-0 rounded-[4px] overflow-hidden shadow-sm">
                            <img src={imageUrl} alt="" className="w-full h-full object-cover" />
                        </div>

                        {/* Text Info */}
                        <div className="flex-1 flex flex-col justify-center min-w-0 pr-2">
                            <span className="text-white font-bold text-xs truncate">
                                {currentSong.name}
                            </span>
                            <span className="text-white/70 text-[10px] truncate">
                                {primaryArtistName}
                            </span>
                        </div>

                        {/* Controls */}
                        <div className="flex items-center gap-1.5 pr-1 shrink-0">
                            {/* Like Button */}
                            <button onClick={(e) => { e.stopPropagation(); toggleLike(currentSong); }} className="shrink-0 p-1.5">
                                <Heart size={20} fill={isLiked ? "#1DB954" : "none"} className={isLiked ? "text-[#1DB954]" : "text-white"} />
                            </button>

                            {/* Previous Button (Hidden on very small screens if needed, but fitting here) */}
                            <button onClick={(e) => { e.stopPropagation(); prevSong(); }} className="shrink-0 p-1.5 text-white/90 hover:text-white">
                                <SkipBack size={22} fill="white" />
                            </button>

                            {/* Play/Pause Button */}
                            <button onClick={(e) => { e.stopPropagation(); togglePlay(); }} className="shrink-0 p-1.5">
                                {isBuffering ? (
                                    <Loader2 size={24} className="animate-spin text-white" />
                                ) : isPlaying ? (
                                    <Pause size={24} fill="white" className="text-white" />
                                ) : (
                                    <Play size={24} fill="white" className="text-white" />
                                )}
                            </button>

                            {/* Next Button */}
                            <button onClick={(e) => { e.stopPropagation(); nextSong(); }} className="shrink-0 p-1.5 text-white/90 hover:text-white">
                                <SkipForward size={22} fill="white" />
                            </button>
                        </div>
                    </div>

                    {/* Progress Bar (Mini only) */}
                    <div className="absolute bottom-0 left-1 right-1 h-[2px] bg-white/20 rounded-full overflow-hidden">
                        <div className="h-full bg-white rounded-full" style={{ width: `${(localProgress / (duration || 1)) * 100}%` }}></div>
                    </div>
                </motion.div>
            )}
        </AnimatePresence>
    </>
  );
};

import React, { useEffect, useState, useRef } from 'react';
import { Play, Pause, SkipBack, SkipForward, ChevronDown, MoreHorizontal, Download, ListMusic, Heart, Loader2, Shuffle, Repeat, PlusCircle, CheckCircle2, Disc, User, Share2, ListPlus, Radio, Mic2, Moon, Info } from 'lucide-react';
import { usePlayerStore } from '../store/playerStore';
import { api, getImageUrl } from '../services/api';
import { AnimatePresence, motion } from 'framer-motion';
import { useNavigate } from 'react-router-dom';

export const Player: React.FC = () => {
  const { 
    currentSong, 
    isPlaying, 
    isBuffering,
    isFullScreen,
    setFullScreen,
    togglePlay, 
    nextSong, 
    prevSong,
    likedSongs,
    toggleLike,
    isShuffling,
    downloadedSongIds,
    addToQueue,
    startDownload,
    duration, 
    audioElement
  } = usePlayerStore();

  const navigate = useNavigate();

  const [dominantColor, setDominantColor] = useState<string>('#121212');
  const [isDragging, setIsDragging] = useState(false);

  const [isMoreMenuOpen, setIsMoreMenuOpen] = useState(false);
  const [isDownloadExpanded, setIsDownloadExpanded] = useState(false);

  const [sleepTimerId, setSleepTimerId] = useState<number | null>(null);
  const [touchStart, setTouchStart] = useState<{x: number, y: number} | null>(null);

  // Direct DOM Refs for High Performance (Zero React Re-renders during playback)
  const fullProgressRef = useRef<HTMLDivElement>(null);
  const fullThumbRef = useRef<HTMLDivElement>(null);
  const fullTimeRef = useRef<HTMLSpanElement>(null);
  const fullRangeRef = useRef<HTMLInputElement>(null);
  const miniProgressRef = useRef<HTMLDivElement>(null);

  const isLiked = currentSong ? likedSongs.some(s => s.id === currentSong.id) : false;
  const isDownloaded = currentSong ? downloadedSongIds.includes(currentSong.id) : false;

  const formatTime = (seconds: number) => {
    if (!seconds || isNaN(seconds)) return "-:--";
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  // PERFORMANCE CORE: Direct DOM updates via requestAnimationFrame
  useEffect(() => {
    let rafId: number;

    const updateUI = () => {
        if (!audioElement || isDragging) return;

        const time = audioElement.currentTime;
        const percent = (time / (duration || 1)) * 100;
        const formattedTime = formatTime(time);

        // Update Full Player
        if (fullProgressRef.current) fullProgressRef.current.style.width = `${percent}%`;
        if (fullThumbRef.current) fullThumbRef.current.style.left = `calc(${percent}% - 7px)`;
        if (fullTimeRef.current) fullTimeRef.current.innerText = formattedTime;
        if (fullRangeRef.current) fullRangeRef.current.value = time.toString();

        // Update Mini Player
        if (miniProgressRef.current) miniProgressRef.current.style.width = `${percent}%`;

        if (isPlaying) {
            rafId = requestAnimationFrame(updateUI);
        }
    };

    if (isPlaying) {
        rafId = requestAnimationFrame(updateUI);
    } else if (audioElement) {
        // Run once to sync UI if paused
        updateUI();
    }

    return () => {
        if (rafId) cancelAnimationFrame(rafId);
    };
  }, [isPlaying, audioElement, duration, isDragging, isFullScreen]);

  // Extract color from image
  useEffect(() => {
    if (!currentSong) return;
    const imgUrl = getImageUrl(currentSong.image);
    const img = new Image();
    img.crossOrigin = "Anonymous";
    img.src = imgUrl;

    img.onload = () => {
      try {
        const canvas = document.createElement('canvas');
        const ctx = canvas.getContext('2d');
        if (!ctx) return;
        canvas.width = 1; 
        canvas.height = 1;
        ctx.drawImage(img, 0, 0, 1, 1);
        const [r, g, b] = ctx.getImageData(0, 0, 1, 1).data;
        setDominantColor(`rgb(${Math.max(20, r - 30)},${Math.max(20, g - 30)},${Math.max(20, b - 30)})`);
      } catch (e) {
        setDominantColor('#181818'); 
      }
    };
    img.onerror = () => setDominantColor('#181818');
  }, [currentSong?.id]);

  // Reset download expansion when menu closes or song changes
  useEffect(() => {
      if (!isMoreMenuOpen) setIsDownloadExpanded(false);
  }, [isMoreMenuOpen, currentSong?.id]);

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const time = parseFloat(e.target.value);

    // Immediate visual update to prevent jumpiness
    if (fullTimeRef.current) fullTimeRef.current.innerText = formatTime(time);
    const percent = (time / (duration || 1)) * 100;
    if (fullProgressRef.current) fullProgressRef.current.style.width = `${percent}%`;
    if (fullThumbRef.current) fullThumbRef.current.style.left = `calc(${percent}% - 7px)`;
    if (miniProgressRef.current) miniProgressRef.current.style.width = `${percent}%`;

    // Seek Audio
    if (audioElement) {
        audioElement.currentTime = time;
    }
  };

  // --- ACTIONS FOR MORE MENU ---
  const handleAddToQueue = () => {
      if(currentSong) {
          addToQueue(currentSong);
          setIsMoreMenuOpen(false);
      }
  };

  const handleShare = async () => {
      if(!currentSong) return;
      const shareData = {
          title: currentSong.name,
          text: `Listen to ${currentSong.name} by ${currentSong.artists.primary[0].name}`,
          url: window.location.href
      };

      if (navigator.share) {
          try {
              await navigator.share(shareData);
          } catch(e) { console.log(e); }
      } else {
          navigator.clipboard.writeText(shareData.url);
      }
      setIsMoreMenuOpen(false);
  };

  const handleSleepTimer = () => {
      if (sleepTimerId) {
          clearTimeout(sleepTimerId);
          setSleepTimerId(null);
      } else {
          // Set for 30 mins
          const id = window.setTimeout(() => {
              if (audioElement) audioElement.pause();
              setSleepTimerId(null);
          }, 30 * 60 * 1000); 
          setSleepTimerId(id);
      }
      setIsMoreMenuOpen(false);
  };

  const handleGoToRadio = async () => {
      if(!currentSong) return;
      setIsMoreMenuOpen(false);

      try {
         const recommendations = await api.getRecommendations(currentSong.id);
         if (recommendations.length > 0) {
             recommendations.forEach(s => addToQueue(s));
             alert(`Added ${recommendations.length} recommended songs to queue.`);
         } else {
             const query = currentSong.artists.primary[0]?.name || currentSong.name;
             const songs = await api.searchSongs(query);
             const newSongs = songs.filter(s => s.id !== currentSong.id);
             if (newSongs.length > 0) {
                 newSongs.slice(0, 10).forEach(s => addToQueue(s));
             }
         }
      } catch(e) {
          console.error("Radio failed", e);
      }
  };

  const handleDownloadSelect = (url: string, quality: string) => {
      if(!currentSong) return;
      const filename = `${currentSong.name} (${quality}) - ${currentSong.artists.primary[0]?.name || 'Artist'}.mp3`;
      startDownload(currentSong, url, filename);
      setIsMoreMenuOpen(false);
      setIsDownloadExpanded(false);
  };

  const handleTouchStart = (e: React.TouchEvent) => {
    setTouchStart({ x: e.targetTouches[0].clientX, y: e.targetTouches[0].clientY });
  };

  const handleTouchEnd = (e: React.TouchEvent) => {
    if (!touchStart) return;
    const touchEndX = e.changedTouches[0].clientX;
    const touchEndY = e.changedTouches[0].clientY;
    const diffX = touchStart.x - touchEndX;
    const diffY = touchStart.y - touchEndY;

    if (Math.abs(diffX) > 50 && Math.abs(diffX) > Math.abs(diffY)) {
      if (diffX > 0) nextSong();
      else prevSong();
    }
    if (diffY < -80 && Math.abs(diffY) > Math.abs(diffX) && !isMoreMenuOpen) {
        setFullScreen(false);
    }
    setTouchStart(null);
  };

  if (!currentSong) return null;

  const imageUrl = getImageUrl(currentSong.image);
  const primaryArtistName = currentSong.artists?.primary?.[0]?.name || "Unknown";

  return (
    <>
        <AnimatePresence mode="wait">
            {isFullScreen ? (
                <motion.div 
                    key="full-player"
                    initial={{ y: "100%" }}
                    animate={{ y: 0 }}
                    exit={{ y: "100%" }}
                    transition={{ type: "spring", damping: 30, stiffness: 300, mass: 0.8 }}
                    className="fixed inset-0 z-[200] flex flex-col bg-[#121212] isolate overflow-hidden"
                    onClick={(e) => e.stopPropagation()}
                    onTouchStart={handleTouchStart}
                    onTouchEnd={handleTouchEnd}
                >
                    {/* Background */}
                    <div 
                        className="absolute inset-0 z-[-1]"
                        style={{ 
                            background: `linear-gradient(to bottom, ${dominantColor}, #121212)`,
                        }}
                    />

                    {/* FULL PLAYER CONTENT */}
                    <div className="relative z-10 flex flex-col h-full px-6 pt-safe-top pb-safe-bottom">

                        {/* Header */}
                        <div className="flex items-center justify-between h-16 shrink-0 mt-2">
                            <button onClick={() => setFullScreen(false)} className="p-2 -ml-2 rounded-full hover:bg-white/10 shrink-0">
                                <ChevronDown size={28} className="text-white" />
                            </button>
                            <span className="text-[11px] font-bold tracking-[0.15em] uppercase text-white/70">
                                Now Playing
                            </span>
                            <button onClick={() => setIsMoreMenuOpen(true)} className="p-2 -mr-2 rounded-full hover:bg-white/10 shrink-0">
                                <MoreHorizontal size={24} className="text-white" />
                            </button>
                        </div>

                        {/* Main Artwork Area */}
                        <div className="flex-1 flex flex-col justify-center min-h-0 relative my-4">
                            <div className="relative w-full aspect-square max-w-[340px] mx-auto shadow-2xl rounded-xl overflow-hidden">
                                <img 
                                    src={imageUrl} 
                                    alt="Cover"
                                    className="w-full h-full object-cover"
                                />
                            </div>
                        </div>

                        {/* Info & Controls */}
                        <div className="flex flex-col gap-6 mb-10">
                            <div className="flex items-center justify-between">
                                <div className="flex flex-col overflow-hidden mr-4 min-w-0">
                                    <h2 className="text-2xl font-bold text-white truncate">
                                        {currentSong.name}
                                    </h2>
                                    <p className="text-lg text-white/70 truncate">
                                        {primaryArtistName}
                                    </p>
                                </div>
                                <button onClick={() => toggleLike(currentSong)} className="shrink-0">
                                    {isLiked ? <CheckCircle2 size={28} className="text-[#1DB954] fill-black" /> : <PlusCircle size={28} className="text-white/70" />}
                                </button>
                            </div>

                            {/* Scrubber - Improved Hit Area */}
                            <div className="flex flex-col gap-2 pt-2">
                                {/* Container with larger height for touch target */}
                                <div className="relative h-6 w-full flex items-center group cursor-pointer">

                                     {/* Background Track */}
                                     <div className="absolute left-0 right-0 h-1.5 bg-white/20 rounded-full overflow-hidden">
                                         {/* Progress Fill */}
                                         <div 
                                            ref={fullProgressRef}
                                            className="h-full bg-white rounded-full transition-all duration-75 ease-out" 
                                            style={{ width: '0%' }}
                                         />
                                     </div>

                                     {/* Thumb (Dot) - Positioned based on progress */}
                                     <div 
                                        ref={fullThumbRef}
                                        className="absolute h-3.5 w-3.5 bg-white rounded-full shadow-md scale-100 transition-transform active:scale-125 z-10 pointer-events-none"
                                        style={{ left: '-7px' }}
                                     />

                                     {/* Interaction Layer (Invisible Input) */}
                                     <input 
                                        ref={fullRangeRef}
                                        type="range" 
                                        min="0" 
                                        max={duration || 100} 
                                        step="any"
                                        defaultValue="0"
                                        onChange={handleSeek}
                                        onMouseDown={() => setIsDragging(true)}
                                        onTouchStart={() => setIsDragging(true)}
                                        onMouseUp={() => setIsDragging(false)}
                                        onTouchEnd={() => setIsDragging(false)}
                                        className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-20"
                                    />
                                </div>
                                <div className="flex justify-between text-[11px] text-white/50 font-mono font-medium -mt-1">
                                    <span ref={fullTimeRef}>0:00</span>
                                    <span>{formatTime(duration)}</span>
                                </div>
                            </div>

                            {/* Controls */}
                            <div className="flex items-center justify-between px-2">
                                <button className={`shrink-0 ${isShuffling ? 'text-[#1DB954]' : 'text-white/40'}`}><Shuffle size={20} /></button>
                                <button onClick={prevSong} className="shrink-0"><SkipBack size={32} className="text-white" fill="white" /></button>
                                <button 
                                    onClick={togglePlay}
                                    className="w-16 h-16 bg-white rounded-full flex items-center justify-center hover:scale-105 active:scale-95 transition-transform shrink-0"
                                >
                                    {isBuffering ? <Loader2 size={32} className="animate-spin text-black" /> : isPlaying ? <Pause size={32} fill="black" className="text-black" /> : <Play size={32} fill="black" className="ml-1 text-black" />}
                                </button>
                                <button onClick={nextSong} className="shrink-0"><SkipForward size={32} className="text-white" fill="white" /></button>
                                <button className="text-white/40 shrink-0"><Repeat size={20} /></button>
                            </div>

                            {/* Bottom Row */}
                            <div className="flex items-center justify-between px-4">
                                <button className="text-white/50 shrink-0 hover:text-white transition-colors p-2">
                                    <Mic2 size={22} />
                                </button>
                                <button className="text-white/50 shrink-0 hover:text-white transition-colors p-2"><ListMusic size={22} /></button>
                            </div>
                        </div>
                    </div>

                    {/* More Menu (Enhanced) */}
                    <AnimatePresence>
                        {isMoreMenuOpen && (
                            <motion.div 
                                initial={{ opacity: 0 }} animate={{ opacity: 1 }} exit={{ opacity: 0 }}
                                className="absolute inset-0 z-[250] bg-black/60 backdrop-blur-sm flex flex-col justify-end"
                                onClick={() => setIsMoreMenuOpen(false)}
                            >
                                <motion.div 
                                    initial={{ y: "100%" }} animate={{ y: 0 }} exit={{ y: "100%" }}
                                    transition={{ type: "tween", ease: "circOut", duration: 0.3 }}
                                    drag="y"
                                    dragConstraints={{ top: 0 }}
                                    dragElastic={{ top: 0, bottom: 0.2 }}
                                    onDragEnd={(_, info) => {
                                        if (info.offset.y > 100 || info.velocity.y > 100) {
                                            setIsMoreMenuOpen(false);
                                        }
                                    }}
                                    className="bg-[#242424] rounded-t-2xl flex flex-col max-h-[85vh] overflow-y-auto pb-6"
                                    onClick={e => e.stopPropagation()}
                                >
                                    {/* Drag Handle */}
                                    <div className="w-full flex justify-center pt-4 pb-2">
                                        <div className="w-10 h-1 bg-white/20 rounded-full"></div>
                                    </div>

                                    {/* Song Context Info */}
                                    <div className="flex items-center gap-3 px-6 pb-4">
                                        <img src={getImageUrl(currentSong.image)} className="w-12 h-12 rounded-md object-cover shadow-lg" alt="" />
                                        <div>
                                            <div className="font-bold text-white text-[15px]">{currentSong.name}</div>
                                            <div className="text-sm text-white/60">{primaryArtistName}</div>
                                        </div>
                                    </div>

                                    {/* Inline Accordion Download UI */}
                                    <div className="px-6 py-2">
                                        <div className={`rounded-xl transition-all border overflow-hidden ${isDownloadExpanded ? 'bg-[#2A2A2A] border-white/10' : 'bg-[#333] border-white/5'}`}>
                                            <button 
                                                onClick={() => { 
                                                    if(isDownloaded) return; // Already downloaded
                                                    setIsDownloadExpanded(!isDownloadExpanded);
                                                }} 
                                                className={`w-full flex items-center justify-between p-4 ${isDownloaded ? 'cursor-default' : 'cursor-pointer'}`}
                                            >
                                                <div className="flex items-center gap-3">
                                                      <div className={`p-2 rounded-full ${isDownloaded ? 'bg-[#1DB954]/20 text-[#1DB954]' : 'bg-white/10 text-white'}`}>
                                                      <Download size={20} />
                                                      </div>
                                                      <div className="flex flex-col items-start">
                                                          <span className={`text-sm font-bold ${isDownloaded ? 'text-[#1DB954]' : 'text-white'}`}>
                                                              {isDownloaded ? 'Downloaded' : 'Download'}
                                                          </span>
                                                          <span className="text-[10px] text-white/50 font-medium">
                                                          {isDownloaded ? 'Available offline' : (isDownloadExpanded ? 'Select Quality' : 'Tap to choose quality')}
                                                          </span>
                                                      </div>
                                                </div>
                                                {isDownloaded ? <CheckCircle2 size={20} className="text-[#1DB954]" /> : (
                                                    <ChevronDown size={20} className={`text-white/50 transition-transform ${isDownloadExpanded ? 'rotate-180' : ''}`} />
                                                )}
                                            </button>

                                            {/* Expanded Options */}
                                            <AnimatePresence>
                                                {isDownloadExpanded && !isDownloaded && (
                                                    <motion.div 
                                                        initial={{ height: 0, opacity: 0 }}
                                                        animate={{ height: 'auto', opacity: 1 }}
                                                        exit={{ height: 0, opacity: 0 }}
                                                        className="border-t border-white/5 bg-[#252525]"
                                                    >
                                                        {(currentSong.downloadUrl && currentSong.downloadUrl.length > 0) ? currentSong.downloadUrl.slice().sort((a,b) => parseInt(b.quality.replace(/\D/g, '')) - parseInt(a.quality.replace(/\D/g, ''))).map((opt) => (
                                                            <button
                                                                key={opt.quality}
                                                                onClick={() => handleDownloadSelect(opt.url, opt.quality)}
                                                                className="w-full flex items-center justify-between px-4 py-3 hover:bg-white/5 transition-colors group border-b border-white/5 last:border-0"
                                                            >
                                                                <div className="flex flex-col items-start">
                                                                    <span className="text-white font-medium text-sm">{opt.quality}</span>
                                                                    <span className="text-[10px] text-white/40 group-hover:text-white/60">
                                                                        {opt.quality.includes('320') ? 'Best Quality (~8MB)' : opt.quality.includes('160') ? 'Good Balance (~4MB)' : 'Data Saver'}
                                                                    </span>
                                                                </div>
                                                                <Download size={16} className="text-white/20 group-hover:text-white" />
                                                            </button>
                                                        )) : (
                                                            <button
                                                                onClick={async () => {
                                                                    const info = await api.getStreamInfo(currentSong.id);
                                                                    if(info?.stream_url) handleDownloadSelect(info.stream_url, 'Standard');
                                                                }}
                                                                className="w-full flex items-center justify-between px-4 py-3 hover:bg-white/5 transition-colors group"
                                                            >
                                                                <div className="flex flex-col items-start">
                                                                    <span className="text-white font-medium text-sm">Download High Quality</span>
                                                                    <span className="text-[10px] text-white/40 group-hover:text-white/60">Fetch & Save</span>
                                                                </div>
                                                                <Download size={16} className="text-white/20 group-hover:text-white" />
                                                            </button>
                                                        )}
                                                    </motion.div>
                                                )}
                                            </AnimatePresence>
                                        </div>
                                    </div>

                                    {/* Menu Actions List */}
                                    <div className="flex flex-col py-2">

                                        <button onClick={() => { toggleLike(currentSong); setIsMoreMenuOpen(false); }} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Heart size={24} className={isLiked ? "text-[#1DB954] fill-[#1DB954]" : "text-white/80"} />
                                            <span className="text-white font-medium">{isLiked ? 'Liked' : 'Like'}</span>
                                        </button>

                                        <button onClick={handleAddToQueue} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <ListPlus size={24} className="text-white/80" />
                                            <span className="text-white font-medium">Add to queue</span>
                                        </button>

                                        <button onClick={handleShare} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Share2 size={24} className="text-white/80" />
                                            <span className="text-white font-medium">Share</span>
                                        </button>

                                        <button onClick={() => { setIsMoreMenuOpen(false); navigate(`/artist/${currentSong.artists.primary[0].id}`, { state: { artist: currentSong.artists.primary[0] } }); }} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <User size={24} className="text-white/80" />
                                            <span className="text-white font-medium">View Artist</span>
                                        </button>

                                        <button onClick={() => { setIsMoreMenuOpen(false); navigate(`/album/${currentSong.album.id}`); }} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Disc size={24} className="text-white/80" />
                                            <span className="text-white font-medium">View Album</span>
                                        </button>

                                        <button onClick={handleSleepTimer} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Moon size={24} className={sleepTimerId ? "text-[#1DB954]" : "text-white/80"} />
                                            <span className="text-white font-medium">{sleepTimerId ? 'Stop Sleep Timer' : 'Sleep Timer (30 mins)'}</span>
                                        </button>

                                        <button onClick={handleGoToRadio} className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Radio size={24} className="text-white/80" />
                                            <span className="text-white font-medium">Go to Song Radio</span>
                                        </button>

                                        <button className="flex items-center gap-4 px-6 py-3.5 hover:bg-white/5 active:bg-black/20 transition-colors">
                                            <Info size={24} className="text-white/80" />
                                            <span className="text-white font-medium">Show credits</span>
                                        </button>

                                    </div>

                                </motion.div>
                            </motion.div>
                        )}
                    </AnimatePresence>
                </motion.div>
            ) : (
                <motion.div 
                    key="mini-player"
                    initial={{ y: 50, opacity: 0 }}
                    animate={{ y: 0, opacity: 1 }}
                    exit={{ y: 50, opacity: 0 }}
                    transition={{ type: "spring", stiffness: 400, damping: 30 }}
                    className="fixed bottom-[68px] md:bottom-4 left-2 right-2 md:left-1/2 md:-translate-x-1/2 md:w-[450px] h-[56px] z-[150] cursor-pointer isolate"
                    onClick={() => setFullScreen(true)}
                >
                    {/* Background */}
                    <div 
                        className="absolute inset-0 z-[-1] rounded-lg shadow-xl overflow-hidden"
                        style={{ backgroundColor: dominantColor }}
                    >
                         <div className="absolute inset-0 bg-black/20" />
                    </div>

                    <div className="flex items-center h-full px-2 gap-3">
                        {/* Image */}
                        <div className="h-10 w-10 shrink-0 rounded-[4px] overflow-hidden shadow-sm">
                            <img src={imageUrl} alt="" className="w-full h-full object-cover" />
                        </div>

                        {/* Text Info */}
                        <div className="flex-1 flex flex-col justify-center min-w-0 pr-2">
                            <span className="text-white font-bold text-xs truncate">
                                {currentSong.name}
                            </span>
                            <span className="text-white/70 text-[10px] truncate">
                                {primaryArtistName}
                            </span>
                        </div>

                        {/* Controls */}
                        <div className="flex items-center gap-1.5 pr-1 shrink-0">
                            {/* Like Button */}
                            <button onClick={(e) => { e.stopPropagation(); toggleLike(currentSong); }} className="shrink-0 p-1.5">
                                <Heart size={20} fill={isLiked ? "#1DB954" : "none"} className={isLiked ? "text-[#1DB954]" : "text-white"} />
                            </button>

                            {/* Previous Button (Hidden on very small screens if needed, but fitting here) */}
                            <button onClick={(e) => { e.stopPropagation(); prevSong(); }} className="shrink-0 p-1.5 text-white/90 hover:text-white">
                                <SkipBack size={22} fill="white" />
                            </button>

                            {/* Play/Pause Button */}
                            <button onClick={(e) => { e.stopPropagation(); togglePlay(); }} className="shrink-0 p-1.5">
                                {isBuffering ? (
                                    <Loader2 size={24} className="animate-spin text-white" />
                                ) : isPlaying ? (
                                    <Pause size={24} fill="white" className="text-white" />
                                ) : (
                                    <Play size={24} fill="white" className="text-white" />
                                )}
                            </button>

                            {/* Next Button */}
                            <button onClick={(e) => { e.stopPropagation(); nextSong(); }} className="shrink-0 p-1.5 text-white/90 hover:text-white">
                                <SkipForward size={22} fill="white" />
                            </button>
                        </div>
                    </div>

                    {/* Progress Bar (Mini only) */}
                    <div className="absolute bottom-0 left-1 right-1 h-[2px] bg-white/20 rounded-full overflow-hidden">
                        <div 
                            ref={miniProgressRef}
                            className="h-full bg-white rounded-full" 
                            style={{ width: '0%' }}
                        ></div>
                    </div>
                </motion.div>
            )}
        </AnimatePresence>
    </>
  );
};

import React, { useRef, useEffect } from 'react';
import { usePlayerStore } from '../store/playerStore';
import { api, getAudioUrl, getOfflineAudioUrl, getImageUrl } from '../services/api';

export const AudioController: React.FC = () => {
  const audioRef = useRef<HTMLAudioElement>(null);
  // Ref to suppress pause events during source change to prevent state thrashing
  const isSwitchingTrack = useRef(false);

  const { 
    currentSong, 
    isPlaying, 
    setIsPlaying, 
    setIsBuffering, 
    nextSong, 
    prevSong,
    setAudioElement,
    setDuration,
    duration,
    streamingQuality,
    isOfflineMode,
    downloadedSongIds
  } = usePlayerStore();

  // Register audio element in store on mount
  useEffect(() => {
    if (audioRef.current) {
        setAudioElement(audioRef.current);
    }
  }, [setAudioElement]);

  // Handle Playback State (Play/Pause)
  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;

    const attemptPlay = async () => {
        try {
            await audio.play();
        } catch (e: any) {
            // AbortError is expected when we interrupt play with pause/load. Ignore it.
            if (e.name !== 'AbortError') {
                console.warn("Play blocked or interrupted", e);
                setIsPlaying(false);
            }
        }
    };

    if (isPlaying && audio.paused) {
        attemptPlay();
    } else if (!isPlaying && !audio.paused) {
        audio.pause();
    }
  }, [isPlaying, setIsPlaying]);

  // Handle Source Loading
  useEffect(() => {
    if (!currentSong || !audioRef.current) return;

    let isCancelled = false;

    const loadSource = async () => {
        let url = '';

        // 1. Check Offline Storage
        if (isOfflineMode || downloadedSongIds.includes(currentSong.id)) {
            const blobUrl = await getOfflineAudioUrl(currentSong.id);
            if (blobUrl) url = blobUrl;
            else if (isOfflineMode) { 
                if (!isCancelled) setIsPlaying(false); 
                return; 
            }
        }

        // 2. Check Standard Download URLs
        if (!url && !isOfflineMode && currentSong.downloadUrl && currentSong.downloadUrl.length > 0) {
             url = getAudioUrl(currentSong.downloadUrl, streamingQuality);
        }

        // 3. Lazy Load Stream
        if (!url && !isOfflineMode) {
             try {
                 if (!isCancelled) setIsBuffering(true);
                 const streamData = await api.getStreamInfo(currentSong.id);
                 if (streamData && streamData.stream_url) {
                     url = streamData.stream_url;
                 }
             } catch(e) {
                 console.error("Failed to fetch stream", e);
             }
        }

        if (isCancelled) return;

        if (url && audioRef.current) {
            // Avoid reloading if same src
            if (audioRef.current.src === url) {
                 if (usePlayerStore.getState().isPlaying && audioRef.current.paused) {
                      audioRef.current.play().catch(() => {});
                 }
                 return;
            }

            // Flag that we are switching tracks to prevent onPause from triggering
            isSwitchingTrack.current = true;

            const shouldPlay = usePlayerStore.getState().isPlaying;
            audioRef.current.src = url;
            // Note: src assignment triggers loading automatically

            if (shouldPlay) {
                 try {
                     await audioRef.current.play();
                 } catch(e: any) {
                     if (e.name !== 'AbortError') {
                         console.warn("Autoplay blocked", e);
                         if (!isCancelled) setIsPlaying(false);
                     }
                 }
            } else {
                 setIsPlaying(false);
            }

            // Reset switching flag after a short delay
            setTimeout(() => {
                isSwitchingTrack.current = false;
            }, 200);
        }
    };

    loadSource();

    return () => {
        isCancelled = true;
    };
  }, [currentSong?.id, streamingQuality, isOfflineMode, downloadedSongIds]);

  // Handle Media Session (Notification Controls)
  useEffect(() => {
    if (!currentSong || !('mediaSession' in navigator)) return;

    const artistName = currentSong.artists?.primary?.[0]?.name || "Unknown";
    const hqImage = getImageUrl(currentSong.image);

    navigator.mediaSession.metadata = new MediaMetadata({
      title: currentSong.name,
      artist: artistName,
      album: currentSong.album?.name || "Single",
      artwork: [
          { src: hqImage, sizes: '512x512', type: 'image/jpeg' },
      ]
    });

    navigator.mediaSession.setActionHandler('play', () => setIsPlaying(true));
    navigator.mediaSession.setActionHandler('pause', () => setIsPlaying(false));
    navigator.mediaSession.setActionHandler('previoustrack', prevSong);
    navigator.mediaSession.setActionHandler('nexttrack', nextSong);

  }, [currentSong, setIsPlaying, prevSong, nextSong]);

  const handleTimeUpdate = () => {
      // PERFORMANCE: Only update store if duration changes significantly
      if (audioRef.current) {
          const dur = audioRef.current.duration;
          if (dur && dur !== Infinity && !isNaN(dur) && Math.abs(dur - duration) > 1) {
              setDuration(dur);
          }
      }
  };

  const handlePause = () => {
      // Ignore pause events caused by track switching
      if (isSwitchingTrack.current) return;

      if (isPlaying && !audioRef.current?.seeking) {
          setIsPlaying(false);
      }
  };

  return (
    <audio 
        ref={audioRef}
        preload="auto"
        onTimeUpdate={handleTimeUpdate}
        onLoadedMetadata={handleTimeUpdate}
        onEnded={nextSong}
        onWaiting={() => setIsBuffering(true)}
        onPlaying={() => setIsBuffering(false)}
        onCanPlay={() => setIsBuffering(false)}
        onPause={handlePause}
        onPlay={() => !isPlaying && setIsPlaying(true)}
        onError={(e) => {
            console.error("Audio playback error", e);
            setIsBuffering(false);
        }}
    />
  );
};

import { create } from 'zustand';
import { persist } from 'zustand/middleware';
import { Song, UserPlaylist, User, Friend, ChatMessage, PartySession, Artist, SearchResult } from '../types';
import { authService } from '../services/auth';
import { downloadSongWithProgress, OfflineStorage } from '../services/api';

interface PlayerState {
  isPlaying: boolean;
  isBuffering: boolean;
  isFullScreen: boolean;
  currentSong: Song | null;
  queue: Song[];
  history: Song[];
  likedSongs: Song[];
  favoriteArtists: Artist[];
  userPlaylists: UserPlaylist[];
  volume: number;
  isShuffling: boolean;
  streamingQuality: 'low' | 'normal' | 'high';
  musicSource: 'local' | 'youtube' | 'both';

  // Search History
  recentSearches: (SearchResult | string)[];

  // Audio Engine State
  audioElement: HTMLAudioElement | null;
  duration: number;

  // Offline & Downloads
  isOfflineMode: boolean;
  downloadedSongIds: string[];
  activeDownload: Song | null;
  downloadProgress: number;

  // Auth
  currentUser: User | null;

  // Social
  friends: Friend[]; // Unified list
  searchResults: { name: string, email: string, image?: string }[];
  activeChatFriendId: string | null;
  partySession: PartySession | null;

  // Realtime Cleanup
  unsubscribers: Function[];

  // Actions
  setAudioElement: (el: HTMLAudioElement) => void;
  setDuration: (duration: number) => void;
  playSong: (song: Song, newQueue?: Song[]) => void;
  togglePlay: () => void;
  setIsPlaying: (isPlaying: boolean) => void;
  setIsBuffering: (isBuffering: boolean) => void;
  setFullScreen: (isFull: boolean) => void;
  nextSong: () => void;
  prevSong: () => void;
  addToQueue: (song: Song) => void;
  setQueue: (songs: Song[]) => void;
  setVolume: (val: number) => void;
  addToHistory: (song: Song) => void;
  toggleLike: (song: Song) => void;
  toggleArtistLike: (artist: Artist) => void;
  createPlaylist: (playlist: UserPlaylist) => void;
  importPlaylist: (playlist: UserPlaylist) => void;
  addSongToPlaylist: (playlistId: string, song: Song) => void;
  removePlaylist: (id: string) => void;
  setStreamingQuality: (quality: 'low' | 'normal' | 'high') => void;
  setMusicSource: (source: 'local' | 'youtube' | 'both') => void;
  startDownload: (song: Song, url: string, filename: string) => Promise<void>;

  // Search History Actions
  addRecentSearch: (item: SearchResult | string) => void;
  removeRecentSearch: (id: string) => void;
  clearRecentSearches: () => void;

  // Network Actions
  setOfflineMode: (isOffline: boolean) => void;

  // Auth Actions
  loginUser: (user: User & { likedSongs?: Song[], history?: Song[], favoriteArtists?: Artist[], chats?: any }) => void;
  logoutUser: () => void;
  syncUserToCloud: (type?: 'public' | 'private' | 'both') => void;
  updateUserProfile: (name: string, image?: string) => void;
  initRealtimeListeners: () => void;

  // Social Actions
  searchUsers: (query: string) => Promise<void>;
  addContact: (email: string) => Promise<void>;
  refreshFriendsActivity: () => Promise<void>;
  openChat: (friendId: string | null) => void;
  sendMessage: (friendId: string, text: string) => void;
  startParty: () => void;
  stopParty: () => void;
}

export const usePlayerStore = create<PlayerState>()(
  persist(
    (set, get) => ({
      isPlaying: false,
      isBuffering: false,
      isFullScreen: false,
      currentSong: null,
      queue: [],
      history: [],
      likedSongs: [],
      favoriteArtists: [],
      userPlaylists: [],
      volume: 1,
      isShuffling: false,
      currentUser: null,
      streamingQuality: 'high',
      musicSource: 'both',
      recentSearches: [],

      // Audio Engine Initial
      audioElement: null,
      duration: 0,

      // Offline State
      isOfflineMode: !navigator.onLine,
      downloadedSongIds: [],
      activeDownload: null,
      downloadProgress: 0,

      // Social Initial State
      friends: [],
      searchResults: [],
      activeChatFriendId: null,
      partySession: null,
      unsubscribers: [],

      setAudioElement: (el) => set({ audioElement: el }),
      setDuration: (duration) => set({ duration }),

      setOfflineMode: (isOffline) => set({ isOfflineMode: isOffline }),

      playSong: (song, newQueue) => {
        const { addToHistory, currentUser } = get();
        addToHistory(song);

        if (currentUser && navigator.onLine) {
            authService.updateUserStatus('listening', song);
        }

        set((state) => ({
          currentSong: song,
          isPlaying: true,
          isBuffering: true, 
          queue: newQueue ? newQueue : state.queue,
          isFullScreen: false, 
        }));
      },

      togglePlay: () => set((state) => ({ isPlaying: !state.isPlaying })),

      setIsPlaying: (isPlaying) => {
          set({ isPlaying });
          const { currentUser, currentSong, isOfflineMode } = get();
          if (currentUser && !isPlaying && !isOfflineMode) {
             authService.updateUserStatus('online', currentSong);
          }
      },

      setIsBuffering: (isBuffering) => set({ isBuffering }),
      setFullScreen: (isFullScreen) => set({ isFullScreen }),

      nextSong: () => {
        const { queue, currentSong, isShuffling } = get();
        if (!currentSong) return;
        const currentIndex = queue.findIndex(s => s.id === currentSong.id);
        let nextIndex = isShuffling ? Math.floor(Math.random() * queue.length) : currentIndex + 1;
        if (nextIndex < queue.length) get().playSong(queue[nextIndex]);
        else set({ isPlaying: false });
      },

      prevSong: () => {
        const { queue, currentSong } = get();
        if (!currentSong) return;
        const currentIndex = queue.findIndex(s => s.id === currentSong.id);
        if (currentIndex - 1 >= 0) get().playSong(queue[currentIndex - 1]);
      },

      addToQueue: (song) => set((state) => ({ queue: [...state.queue, song] })),
      setQueue: (songs) => set({ queue: songs }),
      setVolume: (volume) => set({ volume }),
      setStreamingQuality: (quality) => set({ streamingQuality: quality }),
      setMusicSource: (source) => set({ musicSource: source }),

      addRecentSearch: (item) => set((state) => {
          const newRecent = [item, ...state.recentSearches.filter(i => {
              if (typeof i === 'string' && typeof item === 'string') return i.toLowerCase() !== item.toLowerCase();
              if (typeof i !== 'string' && typeof item !== 'string') return i.id !== item.id;
              // Filter out if types don't match (e.g. replacing a string with an object of same name? unlikely but safe)
              return true;
          })].slice(0, 10);
          return { recentSearches: newRecent };
      }),

      removeRecentSearch: (id) => set((state) => ({
          recentSearches: state.recentSearches.filter(i => {
              if (typeof i === 'string') return i !== id;
              return i.id !== id;
          })
      })),

      clearRecentSearches: () => set({ recentSearches: [] }),

      addToHistory: (song) => {
          set((state) => {
            const newHistory = [song, ...state.history.filter(s => s.id !== song.id)].slice(0, 20);
            if(navigator.onLine) setTimeout(() => get().syncUserToCloud('private'), 1000);
            return { history: newHistory };
          });
      },

      toggleLike: (song) => {
          set((state) => {
            const isLiked = state.likedSongs.some(s => s.id === song.id);
            const newLiked = isLiked ? state.likedSongs.filter(s => s.id !== song.id) : [song, ...state.likedSongs];
            if(navigator.onLine) setTimeout(() => get().syncUserToCloud('private'), 1000);
            return { likedSongs: newLiked };
          });
      },

      toggleArtistLike: (artist) => {
          set((state) => {
              const isLiked = state.favoriteArtists.some(a => a.id === artist.id);
              const newLiked = isLiked 
                  ? state.favoriteArtists.filter(a => a.id !== artist.id) 
                  : [...state.favoriteArtists, artist];
              return { favoriteArtists: newLiked };
          });
      },

      createPlaylist: (playlist) => {
        set((state) => {
           const newPlaylists = [playlist, ...state.userPlaylists];
           if(navigator.onLine) authService.savePublicPlaylist(playlist);
           if (state.currentUser) {
             const updatedUser = { ...state.currentUser, playlists: newPlaylists };
             if(navigator.onLine) setTimeout(() => get().syncUserToCloud('private'), 1000);
             return { userPlaylists: newPlaylists, currentUser: updatedUser };
           }
           return { userPlaylists: newPlaylists };
        });
      },

      importPlaylist: (playlist) => {
        set((state) => {
           if (state.userPlaylists.some(p => p.id === playlist.id)) return {};
           const newPlaylists = [playlist, ...state.userPlaylists];
           if (state.currentUser) {
             const updatedUser = { ...state.currentUser, playlists: newPlaylists };
             if(navigator.onLine) setTimeout(() => get().syncUserToCloud('private'), 1000);
             return { userPlaylists: newPlaylists, currentUser: updatedUser };
           }
           return { userPlaylists: newPlaylists };
        });
      },

      addSongToPlaylist: (playlistId, song) => {
        set((state) => {
          const newPlaylists = state.userPlaylists.map(p => {
            if (p.id === playlistId) {
               const updated = { ...p, songs: [...p.songs, song] };
               if (p.songs.some(s => s.id === song.id)) return p;
               if(navigator.onLine) authService.savePublicPlaylist(updated);
               return updated;
            }
            return p;
          });
          if (state.currentUser) {
             const updatedUser = { ...state.currentUser, playlists: newPlaylists };
             if(navigator.onLine) setTimeout(() => get().syncUserToCloud('private'), 1000);
             return { userPlaylists: newPlaylists, currentUser: updatedUser };
           }
           return { userPlaylists: newPlaylists };
        });
      },

      removePlaylist: (id) => {
        set((state) => {
           const newPlaylists = state.userPlaylists.filter(p => p.id !== id);
           if (state.currentUser) {
             const updatedUser = { ...state.currentUser, playlists: newPlaylists };
             if(navigator.onLine) setTimeout(() => get().syncUserToCloud('private'), 1000);
             return { userPlaylists: newPlaylists, currentUser: updatedUser };
           }
           return { userPlaylists: newPlaylists };
        });
      },

      startDownload: async (song, url, filename) => {
         set({ activeDownload: song, downloadProgress: 0 });
         try {
             await downloadSongWithProgress(song.id, url, filename, (progress) => {
                 set({ downloadProgress: progress });
             });

             // Mark as downloaded in state
             set(state => {
                 const newDownloads = state.downloadedSongIds.includes(song.id) 
                    ? state.downloadedSongIds 
                    : [...state.downloadedSongIds, song.id];
                 return { downloadProgress: 100, downloadedSongIds: newDownloads };
             });

             // Wait a bit before closing progress
             setTimeout(() => {
                 set({ activeDownload: null, downloadProgress: 0 });
             }, 2000);
         } catch (e) {
             console.error("Download Error", e);
             set({ activeDownload: null, downloadProgress: 0 });
         }
      },

      loginUser: (user) => {
          set({ 
            currentUser: user, 
            userPlaylists: user.playlists || [],
            likedSongs: user.likedSongs || [],
            history: user.history || [],
            favoriteArtists: user.favoriteArtists || []
          });
          get().initRealtimeListeners();
      },

      initRealtimeListeners: () => {
         const { unsubscribers, currentUser } = get();
         unsubscribers.forEach(unsub => unsub());

         if (!currentUser || !navigator.onLine) {
             set({ unsubscribers: [] });
             return;
         }

         const newUnsubscribers: Function[] = [];

         const unsubUser = authService.subscribeToUserData((data) => {
             set((state) => {
                 const updatedUser = { ...state.currentUser, ...data } as User;
                 const existingFriends = state.friends;
                 const serverContactEmails = data.friends || [];
                 const serverChats = data.chats || {};

                 const mergedFriends: Friend[] = serverContactEmails.map((email: string) => {
                     const existing = existingFriends.find(f => f.id === email);
                     const chatHistory = serverChats[email] || serverChats[email.replace(/\./g, '_dot_')] || [];
                     return {
                         id: email,
                         name: existing?.name || email.split('@')[0], 
                         image: existing?.image || '',
                         status: existing?.status || 'offline', 
                         currentSong: existing?.currentSong || null, 
                         lastActive: existing?.lastActive || 0,
                         chatHistory: chatHistory
                     };
                 });

                 return {
                     currentUser: updatedUser,
                     friends: mergedFriends,
                     userPlaylists: data.playlists || state.userPlaylists
                 };
             });
         });
         newUnsubscribers.push(unsubUser);

         if (currentUser.friends && currentUser.friends.length > 0) {
             const unsubFriends = authService.subscribeToFriendsActivity(currentUser.friends, (friendsData) => {
                 set((state) => {
                     const updatedFriends = state.friends.map(f => {
                         const liveData = friendsData.find((d: any) => d.email === f.id);
                         if (liveData) {
                             return {
                                 ...f,
                                 name: liveData.name || f.name,
                                 image: liveData.image || f.image,
                                 status: liveData.currentActivity?.status || 'offline',
                                 currentSong: liveData.currentActivity?.song || null,
                                 lastActive: liveData.currentActivity?.timestamp || 0
                             };
                         }
                         return f;
                     });
                     return { friends: updatedFriends };
                 });
             });
             newUnsubscribers.push(unsubFriends);
         }

         set({ unsubscribers: newUnsubscribers });
      },

      logoutUser: async () => {
        get().unsubscribers.forEach(unsub => unsub());
        if(navigator.onLine) await authService.logout();
        set({ 
            currentUser: null, 
            userPlaylists: [],
            friends: [],
            partySession: null,
            likedSongs: [],
            history: [],
            favoriteArtists: [],
            unsubscribers: []
        });
      },

      syncUserToCloud: async (type = 'both') => {
         const { currentUser, userPlaylists, likedSongs, history, favoriteArtists, isOfflineMode } = get();
         if (!currentUser || isOfflineMode) return;
         const updatedUser = { ...currentUser, playlists: userPlaylists };
         try {
             if (type === 'public' || type === 'both') await authService.syncPublicProfile(updatedUser);
             if (type === 'private' || type === 'both') await authService.syncPrivateData(updatedUser, { likedSongs, history, favoriteArtists });
         } catch (e) {
             console.error("Sync failed", e);
         }
      },

      updateUserProfile: (name, image) => {
        set((state) => {
          if (!state.currentUser) return {};
          const updatedUser = { 
              ...state.currentUser, 
              name: name,
              image: image !== undefined ? image : state.currentUser.image 
          };
          setTimeout(() => get().syncUserToCloud('public'), 100);
          return { currentUser: updatedUser };
        });
      },

      searchUsers: async (query) => {
          try {
              if (!navigator.onLine) return;
              const results = await authService.searchUsers(query);
              const { currentUser } = get();
              const filtered = results.filter(u => u.email !== currentUser?.email);
              set({ searchResults: filtered });
          } catch (e) { console.error(e); }
      },

      addContact: async (email) => {
          const { currentUser } = get();
          if (!currentUser || !navigator.onLine) return;
          await authService.addContact(email);
          set((state) => {
              if (state.friends.some(f => f.id === email)) return {};
              const newFriend: Friend = {
                  id: email,
                  name: email.split('@')[0],
                  image: '',
                  status: 'offline',
                  lastActive: 0,
                  chatHistory: []
              };
              return { 
                  friends: [...state.friends, newFriend],
                  activeChatFriendId: email 
              };
          });
          setTimeout(() => {
              get().initRealtimeListeners();
          }, 500);
      },

      refreshFriendsActivity: async () => {
          get().initRealtimeListeners();
      },

      openChat: (friendId) => set({ activeChatFriendId: friendId }),

      sendMessage: async (friendId, text) => {
          const { currentUser } = get();
          if (!currentUser) return;

          const newMessage: ChatMessage = {
              id: `msg-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
              senderId: currentUser.email,
              text,
              timestamp: Date.now()
          };

          set((state) => {
              const updatedFriends = state.friends.map(f => {
                  if (f.id === friendId) {
                      return { ...f, chatHistory: [...f.chatHistory, newMessage] };
                  }
                  return f;
              });
              return { friends: updatedFriends };
          });

          if(navigator.onLine) {
             await authService.sendChatMessage(currentUser.email, friendId, newMessage);
          }
      },

      startParty: () => set((state) => {
         if (!state.currentUser) return {};
         return {
             partySession: {
                 isActive: true,
                 hostId: 'me',
                 hostName: state.currentUser.name,
                 listeners: state.activeChatFriendId ? [state.activeChatFriendId] : []
             }
         }
      }),

      stopParty: () => set({ partySession: null })
    }),
    {
      name: 'vibestream-storage',
      partialize: (state) => ({ 
        history: state.history, 
        volume: state.volume,
        likedSongs: state.likedSongs,
        favoriteArtists: state.favoriteArtists,
        userPlaylists: state.userPlaylists,
        currentUser: state.currentUser,
        streamingQuality: state.streamingQuality,
        musicSource: state.musicSource,
        recentSearches: state.recentSearches, // Persist recent searches
        downloadedSongIds: state.downloadedSongIds,
      }), 
    }
  )
);

