                    <motion.div 
                        key={`${song.id}-${index}`}
                        variants={itemVariants}
                        onClick={() => playSong(song, viewPlaylist.songs)}
                        className={`group grid grid-cols-[16px_1fr_auto] md:grid-cols-[16px_1fr_1fr_auto] gap-4 items-center px-4 py-2 rounded-md cursor-pointer transition-colors ${isCurrent ? 'bg-white/10' : 'hover:bg-white/5'}`}
                    >
                        {/* Index */}
                        <div className="flex items-center justify-center w-4 text-sm font-medium text-[#B3B3B3]">
                            {isCurrent && isPlaying ? (
                                <img src="https://open.spotifycdn.com/cdn/images/equaliser-animated-green.f93a2ef4.gif" className="w-3 h-3" alt="playing" />
                            ) : (
                                <>
                                    <span className={`block group-hover:hidden ${isCurrent ? 'text-[#1DB954]' : ''}`}>{index + 1}</span>
                                    <Play size={12} fill="white" className="hidden group-hover:block text-white" />
                                </>
                            )}
                        </div>

                        {/* Title */}
                        <div className="flex items-center gap-3 overflow-hidden">
                            <img src={getImageUrl(song.image)} alt="" className="w-10 h-10 rounded-[4px] object-cover shadow-sm shrink-0" />
                            <div className="flex flex-col truncate">
                                <span className={`font-medium text-[15px] truncate ${isCurrent ? 'text-[#1DB954]' : 'text-white'}`}>{song.name}</span>
                                <span className="text-xs text-[#B3B3B3] group-hover:text-white truncate transition-colors">{song.artists?.primary?.[0]?.name || "Unknown"}</span>
                            </div>
                        </div>

                        {/* Album */}
                        <span className="hidden md:block text-sm text-[#B3B3B3] truncate group-hover:text-white transition-colors">{song.album?.name || "Single"}</span>

                        {/* Duration */}
                        <div className="flex items-center justify-end gap-3 min-w-[60px]">
                            <button className="opacity-0 group-hover:opacity-100 transition-opacity text-[#B3B3B3] hover:text-white hidden md:block" title="Save to Liked">
                                <Heart size={16} />
                            </button>
                            <span className="text-sm font-mono text-[#B3B3B3]">
                                {Math.floor(parseInt(song.duration) / 60)}:{(parseInt(song.duration) % 60).toString().padStart(2, '0')}
                            </span>
                        </div>
                    </motion.div>
                );
            })}
        </motion.div>

        {/* --- ADD SONGS SECTION --- */}
        {isMyPlaylist && (
            <div className="mt-4 mb-16 border-t border-white/10 pt-8">
                <div className="flex flex-col gap-4 mb-6">
                    <h2 className="text-xl md:text-2xl font-bold text-white">Let's find something for your playlist</h2>
                    <div className="relative max-w-md">
                        <Search size={18} className="absolute left-3 top-1/2 -translate-y-1/2 text-[#B3B3B3]" />
                        <input 
                            type="text" 
                            placeholder="Search for songs" 
                            value={searchQuery}
                            onChange={(e) => setSearchQuery(e.target.value)}
                            className="w-full bg-[#2A2A2A] text-white pl-10 pr-10 py-3 rounded-md focus:outline-none focus:bg-[#333] focus:ring-1 focus:ring-white/20 transition-all placeholder-[#B3B3B3] text-sm font-medium"
                        />
                        {searchQuery && (
                            <button onClick={() => setSearchQuery('')} className="absolute right-3 top-1/2 -translate-y-1/2">
                                 {isSearching ? <div className="w-4 h-4 border-2 border-white/20 border-t-white rounded-full animate-spin"></div> : <div className="text-white/50 hover:text-white">✕</div>}
                            </button>
                        )}
                    </div>
                </div>

                <div className="flex flex-col gap-1">
                    {searchResults.map((song) => {
                        const isAdded = viewPlaylist.songs.some(s => s.id === song.id);
                        return (
                            <div key={song.id} className="flex items-center justify-between p-2 hover:bg-[#2A2A2A] rounded-lg group transition-colors animate-in fade-in slide-in-from-bottom-2 duration-300">
                                <div className="flex items-center gap-3 overflow-hidden">
                                    <img src={getImageUrl(song.image)} className="w-10 h-10 object-cover rounded shadow-sm" alt="" />
                                    <div className="flex flex-col truncate">
                                        <span className="text-white font-medium text-sm truncate">{song.name}</span>
                                        <span className="text-[#B3B3B3] text-xs truncate">{song.artists?.primary?.[0]?.name}</span>
                                    </div>
                                </div>
                                <button 
                                    onClick={() => !isAdded && handleAddSong(song)}
                                    disabled={isAdded}
                                    className={`px-4 py-1.5 rounded-full border text-xs font-bold transition-all ${isAdded ? 'border-transparent text-white/50' : 'border-[#727272] text-white hover:border-white hover:scale-105'}`}
                                >
                                    {isAdded ? 'Added' : 'Add'}
                                </button>
                            </div>
                        )
                    })}
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { useParams, useLocation, useNavigate } from 'react-router-dom';
import { api, getImageUrl } from '../services/api';
import { Artist, Song, Album } from '../types';
import { usePlayerStore } from '../store/playerStore';
import { Play, Pause, CheckCircle2, PlusCircle, ArrowLeft, MoreHorizontal, Disc } from 'lucide-react';
import { motion } from 'framer-motion';

const containerVariants = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: {
      staggerChildren: 0.1
    }
  }
};

const itemVariants = {
  hidden: { opacity: 0, x: -20 },
  visible: { opacity: 1, x: 0 }
};

export const ArtistDetails: React.FC = () => {
  const { id } = useParams<{ id: string }>();
  const location = useLocation();
  const navigate = useNavigate();
  const [artist, setArtist] = useState<Artist | null>(location.state?.artist || null);
  const [songs, setSongs] = useState<Song[]>([]);
  const [albums, setAlbums] = useState<Album[]>([]);
  const [loading, setLoading] = useState(!artist);
  const { playSong, currentSong, isPlaying, toggleLike, likedSongs } = usePlayerStore();

  const [scrollOpacity, setScrollOpacity] = useState(0);

  useEffect(() => {
    const handleScroll = () => {
        const opacity = Math.min(window.scrollY / 200, 1);
        setScrollOpacity(opacity);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  useEffect(() => {
    const fetchData = async () => {
      let currentArtist = artist;

      // 1. Fetch Artist Info if not present
      if (!currentArtist && id) {
        try {
           const results = await api.searchArtists(id);
           if (results.length > 0) {
             currentArtist = results[0];
             setArtist(currentArtist);
           }
        } catch (e) {
           console.error("Failed to fetch artist", e);
        }
      }

      // 2. Fetch Songs and Albums
      if (currentArtist) {
        setLoading(true);
        try {
            const [trackResults, albumResults] = await Promise.all([
                api.searchSongs(currentArtist.name),
                api.searchAlbums(currentArtist.name)
            ]);
            setSongs(trackResults);
            setAlbums(albumResults);
        } catch (e) {
            console.error("Failed to fetch artist details", e);
        } finally {
            setLoading(false);
        }
      } else {
        setLoading(false);
      }
    };

    fetchData();
  }, [id, artist]);

  if (loading) {
     return <div className="flex h-screen w-full items-center justify-center bg-black"><div className="w-8 h-8 border-2 border-white border-t-transparent rounded-full animate-spin"></div></div>;
  }

  if (!artist) {
      return (
          <div className="flex flex-col items-center justify-center h-full gap-4 text-white">
              <span className="text-secondary">Artist not found.</span>
              <button onClick={() => navigate('/search')} className="px-6 py-3 bg-white text-black rounded-full text-sm font-bold">Go to Search</button>
          </div>
      );
  }

  const imageUrl = getImageUrl(artist.image);

  return (
    <div className="min-h-full pb-32 bg-[#121212] text-white relative isolate">

        {/* Sticky Header */}
        <div 
            className="fixed top-0 left-0 right-0 z-40 transition-colors duration-200 flex items-center justify-between px-4 py-3"
            style={{ backgroundColor: `rgba(18, 18, 18, ${scrollOpacity})`, backdropFilter: scrollOpacity > 0.8 ? 'blur(10px)' : 'none' }}
        >
            <button onClick={() => navigate(-1)} className="p-2 rounded-full bg-black/40 hover:bg-black/60 text-white">
                <ArrowLeft size={20} />
            </button>
            <span 
                className="font-bold text-lg transition-opacity duration-300"
                style={{ opacity: scrollOpacity }}
            >
                {artist.name}
            </span>
            <button className="p-2 rounded-full bg-black/40 hover:bg-black/60 text-white">
                <MoreHorizontal size={20} />
            </button>
        </div>

        {/* Hero Image */}
        <div className="relative w-full h-[350px] md:h-[450px] -mt-[64px] z-0">
            <div className="absolute inset-0 bg-gradient-to-b from-transparent via-black/40 to-[#121212] z-10"></div>
            <motion.img 
                initial={{ scale: 1.1 }}
                animate={{ scale: 1 }}
                transition={{ duration: 1 }}
                src={imageUrl} 
                alt={artist.name} 
                className="w-full h-full object-cover object-center" 
            />
            <div className="absolute bottom-0 left-0 p-6 z-20 w-full">
                 <motion.div 
                    initial={{ opacity: 0, x: -20 }}
                    animate={{ opacity: 1, x: 0 }}
                    transition={{ delay: 0.2 }}
                    className="flex items-center gap-2 mb-2"
                 >
                     <CheckCircle2 size={24} className="text-[#3d91f4] fill-white bg-white rounded-full border-none" />
                     <span className="text-sm font-medium tracking-wide">Verified Artist</span>
                 </motion.div>
                 <motion.h1 
                    initial={{ opacity: 0, y: 20 }}
                    animate={{ opacity: 1, y: 0 }}
                    transition={{ delay: 0.3 }}
                    className="text-5xl md:text-7xl font-black text-white drop-shadow-xl"
                >
                    {artist.name}
                 </motion.h1>
                 <motion.p 
                    initial={{ opacity: 0 }}
                    animate={{ opacity: 0.8 }}
                    transition={{ delay: 0.4 }}
                    className="text-white/80 mt-2 font-medium"
                 >
                    10,230,129 monthly listeners
                 </motion.p>
            </div>
        </div>

        {/* Action Buttons */}
        <div className="px-4 py-6 flex items-center gap-4 bg-[#121212] relative z-20">
             <motion.button 
                 initial={{ scale: 0 }}
                 animate={{ scale: 1 }}
                 transition={{ type: "spring", delay: 0.5 }}
                 onClick={() => songs.length > 0 && playSong(songs[0], songs)}
                 className="w-14 h-14 bg-[#1DB954] rounded-full flex items-center justify-center hover:scale-105 active:scale-95 transition-transform shadow-lg"
             >
                 {isPlaying && currentSong?.artists?.primary?.[0]?.name === artist.name ? (
                     <Pause size={28} fill="black" className="text-black" />
                 ) : (
                     <Play size={28} fill="black" className="text-black ml-1" />
                 )}
             </motion.button>
             <button className="px-5 py-2 rounded-full border border-white/40 text-sm font-bold hover:border-white transition-colors">
                 Follow
             </button>
        </div>

        {/* Popular Songs */}
        <div className="px-4 pb-8 bg-[#121212] relative z-20">
            <h2 className="text-xl font-bold mb-4">Popular</h2>
            <motion.div 
                className="flex flex-col"
                variants={containerVariants}
                initial="hidden"
                animate="visible"
            >
                {songs.length === 0 ? (
                    <div className="text-secondary italic">No songs found.</div>
                ) : (
                    songs.slice(0, 5).map((song, index) => {
                        const isCurrent = currentSong?.id === song.id;
                        const isSongLiked = likedSongs.some(s => s.id === song.id);

                        return (
                            <motion.div 
                                key={song.id}
                                variants={itemVariants}
                                onClick={() => playSong(song, songs)}
                                className={`flex items-center gap-4 p-3 rounded-md cursor-pointer transition-colors ${isCurrent ? 'bg-white/10' : 'hover:bg-white/5'}`}
                            >
                                <span className={`w-4 text-center text-sm font-mono ${isCurrent ? 'text-[#1DB954]' : 'text-[#B3B3B3]'}`}>
                                    {index + 1}
                                </span>

                                <img src={getImageUrl(song.image)} className="w-10 h-10 rounded object-cover" alt="" />

                                <div className="flex-1 min-w-0">
                                    <div className={`font-medium truncate text-[15px] ${isCurrent ? 'text-[#1DB954]' : 'text-white'}`}>
                                        {song.name}
                                    </div>
                                    <div className="text-xs text-[#B3B3B3] truncate">
                                        {song.downloadUrl?.some(u => u.quality.includes('320')) && (
                                            <span className="bg-[#555] text-white px-1 rounded-[2px] text-[9px] mr-1">E</span>
                                        )}
                                        {song.artists.primary[0]?.name}
                                    </div>
                                </div>

                                <span className="text-xs text-[#B3B3B3] font-mono hidden md:block">
                                    {(parseInt(song.duration) / 60).toFixed(0)}:{(parseInt(song.duration) % 60).toString().padStart(2, '0')}
                                </span>

                                <button 
                                    onClick={(e) => { e.stopPropagation(); toggleLike(song); }}
                                    className={`${isSongLiked ? 'text-[#1DB954]' : 'text-[#B3B3B3] hover:text-white'}`}
                                >
                                    {isSongLiked ? <CheckCircle2 size={18} /> : <PlusCircle size={18} />}
                                </button>
                            </motion.div>
                        );
                    })
                )}
            </motion.div>
        </div>

        {/* Albums Section */}
        {albums.length > 0 && (
            <div className="px-4 pb-8 bg-[#121212] relative z-20">
                <h2 className="text-xl font-bold mb-4">Discography</h2>
                <div className="flex overflow-x-auto gap-4 no-scrollbar pb-2">
                    {albums.map((album) => (
                        <motion.div 
                            key={album.id} 
                            whileHover={{ y: -5 }}
                            className="w-[150px] shrink-0 cursor-pointer group"
                            onClick={() => navigate(`/album/${album.id}`)}
                        >
                            <div className="w-full aspect-square mb-2 relative">
                                <img src={getImageUrl(album.image)} alt={album.name} className="w-full h-full object-cover rounded-md shadow-md" />
                            </div>
                            <h3 className="text-sm font-bold text-white truncate group-hover:underline">{album.name}</h3>
                            <p className="text-xs text-[#B3B3B3]">{album.year} • Album</p>
                        </motion.div>
                    ))}
                </div>
            </div>
        )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { X, Upload, Loader2, Music, Sparkles, Search, Plus } from 'lucide-react';
import { uploadToCloudinary, api, getImageUrl } from '../services/api';
import { usePlayerStore } from '../store/playerStore';
import { UserPlaylist, Song } from '../types';
import { motion } from 'framer-motion';

interface CreatePlaylistModalProps {
  onClose: () => void;
}

export const CreatePlaylistModal: React.FC<CreatePlaylistModalProps> = ({ onClose }) => {
  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const [file, setFile] = useState<File | null>(null);
  const [preview, setPreview] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(false);

  // AI Smart Fill State
  const [seedQuery, setSeedQuery] = useState('');
  const [seedResults, setSeedResults] = useState<Song[]>([]);
  const [selectedSeed, setSelectedSeed] = useState<Song | null>(null);
  const [isSearchingSeed, setIsSearchingSeed] = useState(false);

  const fileInputRef = useRef<HTMLInputElement>(null);
  const { createPlaylist } = usePlayerStore();

  // Search for seed songs
  useEffect(() => {
    const timer = setTimeout(async () => {
        if (seedQuery.trim() && !selectedSeed) {
            setIsSearchingSeed(true);
            try {
                const results = await api.searchSongs(seedQuery);
                setSeedResults(results.slice(0, 4));
            } catch (e) {
                console.error(e);
            } finally {
                setIsSearchingSeed(false);
            }
        }
    }, 500);
    return () => clearTimeout(timer);
  }, [seedQuery, selectedSeed]);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const selectedFile = e.target.files[0];
      setFile(selectedFile);
      setPreview(URL.createObjectURL(selectedFile));
    }
  };

  const handleSelectSeed = (song: Song) => {
      setSelectedSeed(song);
      setSeedQuery(song.name);
      setSeedResults([]); // Hide dropdown
      // Auto-name playlist if empty
      if (!name) setName(`${song.name} Radio`);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!name.trim()) return;

    setIsLoading(true);
    try {
      let imageUrl = 'https://images.unsplash.com/photo-1614613535308-eb5fbd3d2c17?q=80&w=500&auto=format&fit=crop';

      if (file) {
        imageUrl = await uploadToCloudinary(file);
      } else if (selectedSeed) {
        // Use seed song image if no custom upload
        imageUrl = getImageUrl(selectedSeed.image);
      }

      let initialSongs: Song[] = [];

      // AI Logic: Fetch similar songs
      if (selectedSeed) {
          const artistName = selectedSeed.artists.primary[0]?.name || '';
          // Search for a mix of artist and genre-like queries
          const similarSongs = await api.searchSongs(`${artistName} ${selectedSeed.language || ''}`);
          // Filter out duplicates
          initialSongs = [selectedSeed, ...similarSongs.filter(s => s.id !== selectedSeed.id).slice(0, 15)];
      }

      const newPlaylist: UserPlaylist = {
        id: `user-pl-${Date.now()}`,
        title: name,
        subtitle: selectedSeed ? `Based on ${selectedSeed.name}` : (description || 'User Playlist'),
        description: description,
        type: 'playlist',
        isUserCreated: true,
        createdAt: Date.now(),
        image: [{ quality: 'high', url: imageUrl }],
        songs: initialSongs
      };

      createPlaylist(newPlaylist);
      onClose();
    } catch (error) {
      console.error('Failed to create playlist', error);
      alert('Failed to upload image or create playlist. Please try again.');
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="fixed inset-0 z-[250] flex items-end md:items-center justify-center p-0 md:p-4 bg-black/80 backdrop-blur-md">
      <motion.div 
        initial={{ y: 50, opacity: 0, scale: 0.95 }}
        animate={{ y: 0, opacity: 1, scale: 1 }}
        exit={{ y: 50, opacity: 0, scale: 0.95 }}
        transition={{ type: "spring", damping: 25, stiffness: 300 }}
        className="bg-[#121212] w-full max-w-lg rounded-t-2xl md:rounded-2xl border border-white/10 shadow-2xl overflow-hidden flex flex-col max-h-[95dvh]"
      >

        {/* Header */}
        <div className="flex items-center justify-between p-4 border-b border-white/5 bg-[#121212]">
            <h2 className="text-xl font-bold text-white flex items-center gap-2">
                Create Playlist
                {selectedSeed && <Sparkles size={16} className="text-[#1DB954]" />}
            </h2>
            <button onClick={onClose} className="p-2 hover:bg-white/10 rounded-full text-white/70 hover:text-white transition-colors">
                <X size={20} />
            </button>
        </div>

        {/* Content */}
        <div className="overflow-y-auto no-scrollbar">
            <form onSubmit={handleSubmit} className="p-6 flex flex-col gap-6">

                <div className="flex flex-col md:flex-row gap-6">
                    {/* Image Upload */}
                    <div className="flex justify-center shrink-0">
                        <div 
                            onClick={() => fileInputRef.current?.click()}
                            className="w-40 h-40 bg-[#282828] rounded-lg flex flex-col items-center justify-center cursor-pointer hover:bg-[#333] transition-colors group relative overflow-hidden border-2 border-dashed border-white/10 hover:border-white/30 shadow-inner"
                        >
                            {preview ? (
                                <img src={preview} alt="Preview" className="w-full h-full object-cover" />
                            ) : selectedSeed ? (
                                <img src={getImageUrl(selectedSeed.image)} alt="Seed" className="w-full h-full object-cover opacity-60" />
                            ) : (
                                <>
                                    <Music size={40} className="text-white/20 group-hover:text-white/40 mb-2 transition-colors" />
                                    <span className="text-xs text-white/50 font-medium text-center px-2">Tap to upload cover</span>
                                </>
                            )}

                            <div className="absolute inset-0 bg-black/50 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                                <Upload size={24} className="text-white" />
                            </div>
                        </div>
                        <input 
                            type="file" 
                            ref={fileInputRef} 
                            className="hidden" 
                            accept="image/*"
                            onChange={handleFileChange}
                        />
                    </div>

                    {/* Inputs */}
                    <div className="space-y-4 flex-1">
                        <div className="flex flex-col gap-1.5">
                            <label className="text-xs font-bold text-white/70 uppercase tracking-wider">Name</label>
                            <input 
                                type="text" 
                                value={name}
                                onChange={(e) => setName(e.target.value)}
                                placeholder="My Playlist"
                                className="bg-[#282828] text-white p-3 rounded-md focus:outline-none focus:ring-1 focus:ring-white/30 font-medium w-full"
                                autoFocus={!selectedSeed}
                            />
                        </div>
                        <div className="flex flex-col gap-1.5">
                            <label className="text-xs font-bold text-white/70 uppercase tracking-wider">Description</label>
                            <textarea 
                                value={description}
                                onChange={(e) => setDescription(e.target.value)}
                                placeholder="Add an optional description"
                                className="bg-[#282828] text-white p-3 rounded-md focus:outline-none focus:ring-1 focus:ring-white/30 resize-none h-20 text-sm w-full"
                            />
                        </div>
                    </div>
                </div>

                {/* AI Smart Fill Section */}
                <div className="bg-gradient-to-r from-[#1DB954]/10 to-transparent p-4 rounded-xl border border-[#1DB954]/20 relative">
                    <div className="flex items-center gap-2 mb-3">
                        <Sparkles size={18} className="text-[#1DB954]" />
                        <span className="text-sm font-bold text-white">AI Smart Fill</span>
                    </div>

                    {!selectedSeed ? (
                        <div className="relative">
                            <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-white/50" />
                            <input 
                                type="text"
                                value={seedQuery}
                                onChange={(e) => setSeedQuery(e.target.value)}
                                placeholder="Pick a song to auto-fill playlist..."
                                className="w-full bg-[#121212] text-white pl-9 pr-4 py-2.5 rounded-lg text-sm border border-white/10 focus:border-[#1DB954] focus:outline-none transition-colors"
                            />
                            {isSearchingSeed && <Loader2 size={16} className="animate-spin absolute right-3 top-1/2 -translate-y-1/2 text-white/50" />}

                            {/* Dropdown Results */}
                            {seedResults.length > 0 && (
                                <div className="absolute top-full left-0 right-0 mt-2 bg-[#181818] border border-white/10 rounded-lg shadow-xl z-20 overflow-hidden">
                                    {seedResults.map(song => (
                                        <div 
                                            key={song.id} 
                                            onClick={() => handleSelectSeed(song)}
                                            className="flex items-center gap-3 p-2 hover:bg-white/10 cursor-pointer transition-colors"
                                        >
                                            <img src={getImageUrl(song.image)} className="w-8 h-8 rounded object-cover" alt="" />
                                            <div className="flex flex-col overflow-hidden">
                                                <span className="text-sm font-medium text-white truncate">{song.name}</span>
                                                <span className="text-xs text-[#777] truncate">{song.artists.primary[0]?.name}</span>
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    ) : (
                        <div className="flex items-center justify-between bg-[#1DB954]/20 p-2 rounded-lg border border-[#1DB954]/30">
                            <div className="flex items-center gap-3">
