// Enhanced Page Transition for Glass Feel
const PageTransition: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  return (
    <motion.div
      initial={{ opacity: 0, scale: 0.98, filter: 'blur(10px)' }}
      animate={{ opacity: 1, scale: 1, filter: 'blur(0px)' }}
      exit={{ opacity: 0, scale: 0.98, filter: 'blur(10px)' }}
      transition={{ duration: 0.4, ease: [0.22, 1, 0.36, 1] }}
      className="h-full w-full"
    >
      {children}
    </motion.div>
  );
};

// Animated Routes Component
const AnimatedRoutes: React.FC = () => {
  const location = useLocation();

  return (
    <AnimatePresence mode="wait">
      <Routes location={location} key={location.pathname}>
        <Route path="/" element={<PageTransition><Home /></PageTransition>} />
        <Route path="/search" element={<PageTransition><Search /></PageTransition>} />
        <Route path="/library" element={<PageTransition><Library /></PageTransition>} />
        <Route path="/social" element={<PageTransition><Social /></PageTransition>} />
        <Route path="/why-us" element={<PageTransition><WhyUs /></PageTransition>} />
        <Route path="/album/:id" element={<PageTransition><AlbumDetails /></PageTransition>} />
        <Route path="/artist/:id" element={<PageTransition><ArtistDetails /></PageTransition>} />
        <Route path="/playlist/:id" element={<PageTransition><PlaylistDetails /></PageTransition>} />
        <Route path="/premium" element={<PageTransition><LoginPromo /></PageTransition>} />
        <Route path="/liked" element={<PageTransition><LikedSongs /></PageTransition>} />
        <Route path="/login" element={<PageTransition><Login /></PageTransition>} />
        <Route path="/signup" element={<PageTransition><Signup /></PageTransition>} />
        <Route path="/profile" element={<PageTransition><Profile /></PageTransition>} />
        <Route path="/artists/select" element={<PageTransition><ArtistSelection /></PageTransition>} />
      </Routes>
    </AnimatePresence>
  );
};

// Layout wrapper to handle scroll behavior and structure
const Layout: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const location = useLocation();
  const { isOfflineMode } = usePlayerStore();
  const isFullScreenPage = ['/premium', '/login', '/signup', '/artists/select'].includes(location.pathname);
  const mainRef = useRef<HTMLElement>(null);

  useEffect(() => {
    if (mainRef.current) {
      mainRef.current.scrollTo({ top: 0, behavior: 'smooth' });
    }
  }, [location.pathname]);

  return (
    <div className="flex h-[100dvh] w-screen overflow-hidden relative">
      <AudioController /> 

      {!isFullScreenPage && <Sidebar />}

      {/* Global Offline Indicator */}
      <AnimatePresence>
          {isOfflineMode && !isFullScreenPage && (
              <motion.div 
                initial={{ y: -50, opacity: 0 }}
                animate={{ y: 0, opacity: 1 }}
                exit={{ y: -50, opacity: 0 }}
                className="absolute top-4 left-0 right-0 z-[100] flex justify-center pointer-events-none"
              >
                  <div className="vision-glass px-4 py-2 flex items-center gap-2 text-xs font-bold text-[#B3B3B3] rounded-full shadow-lg">
                      <WifiOff size={12} />
                      <span>Offline Mode</span>
                  </div>
              </motion.div>
          )}
      </AnimatePresence>

      <main 
        ref={mainRef}
        className={`flex-1 relative overflow-y-auto no-scrollbar overscroll-none md:my-3 md:mr-3 rounded-3xl ${
          isFullScreenPage ? 'z-50 !m-0 !rounded-none' : 'vision-glass'
        }`}
        style={{
          // For full screen pages we want transparency to see the mesh
          // For the main panel we want the glass effect
          background: isFullScreenPage ? 'transparent' : undefined
        }}
      >
         {/* Main Content */}
        {children}
        {/* Spacer */}
        {!isFullScreenPage && <div className="h-32 md:h-24 w-full"></div>}
      </main>

      {!isFullScreenPage && <DownloadProgress />}
      {!isFullScreenPage && <Player />}
      {!isFullScreenPage && <BottomNav />}
    </div>
  );
};

const App: React.FC = () => {
  const { setOfflineMode } = usePlayerStore();

  useEffect(() => {
    const handleOnline = () => setOfflineMode(false);
    const handleOffline = () => setOfflineMode(true);

    window.addEventListener('online', handleOnline);
    window.addEventListener('offline', handleOffline);

    setOfflineMode(!navigator.onLine);

    return () => {
      window.removeEventListener('online', handleOnline);
      window.removeEventListener('offline', handleOffline);
    };
  }, [setOfflineMode]);

  return (
    <HashRouter>
      <Layout>
        <AnimatedRoutes />
      </Layout>
    </HashRouter>
  );
};

export default App;

