                    animate={{ opacity: 1, scale: 1, y: 0, filter: 'blur(0px)' }}
                    exit={{ opacity: 0, scale: 0.9, y: 50, filter: 'blur(10px)' }}
                    transition={{ type: "spring", damping: 25, stiffness: 200 }}
                    className="fixed inset-0 md:inset-4 z-[200] flex flex-col overflow-hidden isolate shadow-2xl md:rounded-[40px] border border-white/10"
                    style={{ 
                        background: 'rgba(20,20,20,0.75)',
                        backdropFilter: 'blur(60px) saturate(180%)',
                    }}
                >
                    {/* Dynamic Mesh Background within Player */}
                    <div className="absolute inset-0 z-[-1] opacity-50 pointer-events-none">
                         <div className="absolute top-[-50%] left-[-50%] w-[200%] h-[200%] bg-gradient-to-br from-[#1DB954]/20 via-black to-blue-500/10 animate-[spin-slow_20s_linear_infinite]"></div>
                    </div>

                    <div className="relative z-10 flex flex-col h-full px-8 py-8 md:py-10">

                        <div className="flex items-center justify-between h-12 shrink-0">
                            <button onClick={() => setFullScreen(false)} className="p-3 bg-white/5 rounded-full hover:bg-white/20 transition-colors backdrop-blur-md">
                                <ChevronDown size={28} className="text-white" />
                            </button>
                            <div className="flex flex-col items-center">
                                <span className="text-[11px] font-bold tracking-[0.2em] uppercase text-white/50">Playing Now</span>
                                <span className="text-xs font-bold text-white drop-shadow-md">Liked Songs</span>
                            </div>
                            <button onClick={() => setIsMoreMenuOpen(true)} className="p-3 bg-white/5 rounded-full hover:bg-white/20 transition-colors backdrop-blur-md">
                                <MoreHorizontal size={28} className="text-white" />
                            </button>
                        </div>

                        <div className="flex-1 flex flex-col justify-center min-h-0 relative my-6">
                            <motion.div 
                                className="relative w-full aspect-square max-w-[400px] mx-auto rounded-[32px] overflow-hidden shadow-[0_30px_60px_-15px_rgba(0,0,0,0.8)] border border-white/10"
                                whileHover={{ scale: 1.02, rotate: 1 }}
                                transition={{ type: "spring", stiffness: 300 }}
                            >
                                <img src={imageUrl} alt="Cover" className="w-full h-full object-cover" />
                                {/* Glossy Reflection overlay */}
                                <div className="absolute inset-0 bg-gradient-to-tr from-white/10 to-transparent opacity-50 pointer-events-none"></div>
                            </motion.div>
                        </div>

                        <div className="flex flex-col gap-10 mb-8 max-w-[500px] mx-auto w-full">
                            <div className="flex items-center justify-between">
                                <div className="flex flex-col overflow-hidden mr-4">
                                    <h2 className="text-3xl font-black text-white truncate leading-tight drop-shadow-lg">{currentSong.name}</h2>
                                    <p className="text-xl font-medium text-white/70 truncate">{currentSong.artists.primary[0]?.name}</p>
                                </div>
                                <button onClick={() => toggleLike(currentSong)} className="p-4 rounded-full hover:bg-white/10 transition-colors backdrop-blur-sm">
                                    <Heart size={36} fill={isLiked ? "#1DB954" : "none"} className={isLiked ? "text-[#1DB954]" : "text-white/60"} />
                                </button>
                            </div>

                            {/* Volumetric Slider */}
                            <div className="flex flex-col gap-2">
                                <div className="relative h-3 w-full flex items-center group cursor-pointer">
                                     <div className="absolute left-0 right-0 h-1.5 bg-white/10 rounded-full overflow-hidden backdrop-blur-md border border-white/5">
                                         <div ref={fullProgressRef} className="h-full bg-white rounded-full shadow-[0_0_15px_rgba(255,255,255,0.8)]" style={{ width: '0%' }} />
                                     </div>
                                     <div ref={fullThumbRef} className="absolute h-6 w-6 bg-white rounded-full shadow-[0_4px_12px_rgba(0,0,0,0.5)] scale-0 group-hover:scale-100 transition-transform flex items-center justify-center border border-black/10" style={{ left: '-7px' }}></div>
                                     <input 
                                        ref={fullRangeRef} type="range" min="0" max={duration || 100} step="any" defaultValue="0"
                                        onChange={handleSeek} onMouseDown={() => setIsDragging(true)} onMouseUp={() => setIsDragging(false)} onTouchStart={() => setIsDragging(true)} onTouchEnd={() => setIsDragging(false)}
                                        className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-20"
                                    />
                                </div>
                                <div className="flex justify-between text-xs text-white/50 font-bold font-mono px-1">
                                    <span ref={fullTimeRef}>0:00</span>
                                    <span>{formatTime(duration)}</span>
                                </div>
                            </div>

                            <div className="flex items-center justify-between px-2">
                                <button className="text-white/40 hover:text-white transition-colors p-2"><Shuffle size={28} /></button>
                                <button onClick={prevSong} className="p-2 hover:scale-110 transition-transform active:scale-90"><SkipBack size={48} fill="white" className="text-white" /></button>
                                <button onClick={togglePlay} className="w-24 h-24 bg-white rounded-full flex items-center justify-center hover:scale-105 transition-transform shadow-[0_0_50px_rgba(255,255,255,0.2)] active:scale-95">
                                    {isBuffering ? <Loader2 size={48} className="animate-spin text-black" /> : isPlaying ? <Pause size={48} fill="black" className="text-black" /> : <Play size={48} fill="black" className="ml-2 text-black" />}
                                </button>
                                <button onClick={nextSong} className="p-2 hover:scale-110 transition-transform active:scale-90"><SkipForward size={48} fill="white" className="text-white" /></button>
                                <button className="text-white/40 hover:text-white transition-colors p-2"><Repeat size={28} /></button>
