                <motion.div 
                    key="mini-player"
                    initial={{ y: 120, opacity: 0, scale: 0.8 }}
                    animate={{ y: 0, opacity: 1, scale: 1 }}
                    exit={{ y: 120, opacity: 0, scale: 0.8 }}
                    transition={{ type: "spring", stiffness: 280, damping: 20 }}
